#[test]
fn exact_named_booleans_handle_certified_aabb_disjoint_meshes() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 1, 0, 0, 0, 1, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        &[10, 0, 0, 11, 0, 0, 10, 1, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    let union = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    union.validate().unwrap();
    assert_eq!(
        union.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::BoundsDisjoint
        }
    );
    let mut bad_shortcut = union.clone();
    bad_shortcut.graph_had_unknowns = true;
    assert_eq!(
        bad_shortcut.validate().unwrap_err(),
        hypermesh::ExactReportValidationError::ShortcutResultHasUnknownGraph
    );
    assert_eq!(union.mesh.triangles().len(), 2);
    assert_eq!(union.mesh.vertices().len(), 6);

    let intersection = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert!(intersection.mesh.triangles().is_empty());
    assert!(intersection.mesh.vertices().is_empty());

    let difference = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert_eq!(difference.mesh.triangles(), left.triangles());
    assert_eq!(difference.mesh.vertices(), left.vertices());

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedBoundsDisjoint
    );
    assert_eq!(preflight.retained_face_pairs, 0);
    assert!(preflight.region_classifications.is_empty());
}

#[test]
fn exact_preflight_materializes_open_point_touch_union_but_keeps_other_ops_boundary_policy() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 2, 0, 0, 0, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        &[2, 0, 0, 4, 0, 0, 2, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    preflight.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let open_intersection_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    open_intersection_preflight.validate().unwrap();
    open_intersection_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        open_intersection_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let open_difference_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    open_difference_preflight.validate().unwrap();
    open_difference_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        open_difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    assert!(!open_intersection_preflight.graph_had_unknowns);
    assert_eq!(open_intersection_preflight.retained_face_pairs, 1);
    assert_eq!(open_intersection_preflight.retained_events, 6);
    assert_eq!(preflight.region_count, 0);
    assert!(preflight.region_classifications.is_empty());
    assert!(open_intersection_preflight.blocker.is_none());
    assert!(open_difference_preflight.blocker.is_none());
    let boundary_report = hypermesh::certify_boundary_touching_report(&left, &right).unwrap();
    boundary_report.validate().unwrap();
    boundary_report
        .validate_against_sources(&left, &right)
        .unwrap();
    assert!(boundary_report.is_certified());
    assert_eq!(
        boundary_report.status,
        hypermesh::ExactBoundaryTouchingStatus::Certified
    );
    assert!(!boundary_report.graph_had_unknowns);
    assert_eq!(boundary_report.retained_face_pairs, 1);
    assert_eq!(boundary_report.blocker.coplanar_touching_pairs, 1);
    assert_eq!(boundary_report.blocker.candidate_pairs, 0);
    let winding_report = hypermesh::certify_winding_readiness_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
    )
    .unwrap();
    winding_report.validate().unwrap();
    winding_report
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        winding_report.status,
        hypermesh::ExactWindingReadinessStatus::BoundaryPolicyRequired
    );
    assert_eq!(
        winding_report.blocker.kind,
        hypermesh::ExactBooleanBlockerKind::NeedsBoundaryPolicy
    );

    let union = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    union
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        union.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    let intersection_result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    intersection_result
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection_result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(intersection_result.mesh.triangles().is_empty());
    let difference_result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    difference_result
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        difference_result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(difference_result.mesh.triangles(), left.triangles());

    let policy_union = hypermesh::boolean_exact_with_boundary_policy(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
        hypermesh::ExactBoundaryBooleanPolicy::PreserveSeparateShells,
    )
    .unwrap();
    policy_union.validate().unwrap();
    assert_eq!(
        policy_union.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(policy_union.mesh.triangles().len(), 2);
    assert_eq!(policy_union.mesh.vertices().len(), 6);

    let intersection = hypermesh::boolean_exact_with_boundary_policy(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::ALLOW_BOUNDARY,
        hypermesh::ExactBoundaryBooleanPolicy::PreserveSeparateShells,
    )
    .unwrap();
    assert!(intersection.mesh.triangles().is_empty());
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );

    let difference = hypermesh::boolean_exact_with_boundary_policy(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::ALLOW_BOUNDARY,
        hypermesh::ExactBoundaryBooleanPolicy::PreserveSeparateShells,
    )
    .unwrap();
    assert_eq!(difference.mesh.triangles(), left.triangles());
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
}

#[test]
fn exact_closed_full_face_overlap_contact_materializes_adjacent_union() {
    let left = axis_aligned_box_i64([0, 0, -2], [2, 2, 0]);
    let right = top_subdivided_axis_aligned_box_i64([0, 0, 0], [2, 2, 2]);

    let graph = build_intersection_graph(&left, &right).unwrap();
    assert!(!graph.has_unknowns());
    assert!(
        graph
            .face_pairs
            .iter()
            .any(|pair| { pair.relation == hypermesh::MeshFacePairRelation::CoplanarOverlapping })
    );
    assert!(graph.face_pairs.iter().all(|pair| {
        pair.relation != hypermesh::MeshFacePairRelation::Candidate
            || pair.events.iter().all(|event| {
                !matches!(
                    event,
                    IntersectionEvent::SegmentPlane {
                        relation: SegmentPlaneRelation::ProperCrossing
                            | SegmentPlaneRelation::ConstructionFailed
                            | SegmentPlaneRelation::Unknown,
                        ..
                    } | IntersectionEvent::Unknown
                )
            })
    }));

    let left_in_right =
        hypermesh::classify_mesh_vertices_against_closed_mesh_winding_report(&left, &right);
    let right_in_left =
        hypermesh::classify_mesh_vertices_against_closed_mesh_winding_report(&right, &left);
    left_in_right
        .validate_against_sources(&left, &right)
        .unwrap();
    right_in_left
        .validate_against_sources(&right, &left)
        .unwrap();
    assert!(
        left_in_right
            .vertices
            .iter()
            .all(|vertex| { vertex.relation != hypermesh::ClosedMeshWindingRelation::Inside })
    );
    assert!(
        right_in_left
            .vertices
            .iter()
            .all(|vertex| { vertex.relation != hypermesh::ClosedMeshWindingRelation::Inside })
    );

    let boundary_report = hypermesh::certify_boundary_touching_report(&left, &right).unwrap();
    boundary_report.validate().unwrap();
    boundary_report
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        boundary_report.status,
        hypermesh::ExactBoundaryTouchingStatus::Certified
    );
    assert!(boundary_report.blocker.coplanar_overlapping_pairs > 0);

    let planar_report = hypermesh::certify_planar_arrangement_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
    )
    .unwrap();
    planar_report.validate().unwrap();
    assert_eq!(
        planar_report.status,
        hypermesh::ExactPlanarArrangementStatus::BoundaryPolicyRequired
    );
    assert_eq!(
        planar_report.blocker.kind,
        hypermesh::ExactBooleanBlockerKind::NeedsBoundaryPolicy
    );

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    assert!(preflight.blocker.is_none());

    let union = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    union.validate().unwrap();
    union
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        union.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(union.mesh.vertices().len(), 8);
    assert_eq!(union.mesh.triangles().len(), 12);
    assert!(union.mesh.facts().mesh.closed_manifold);
    let union_bounds = union.mesh.bounds().mesh.as_ref().unwrap();
    assert_real_eq(&union_bounds.min.x, &Real::from(0));
    assert_real_eq(&union_bounds.max.x, &Real::from(2));
    assert_real_eq(&union_bounds.min.y, &Real::from(0));
    assert_real_eq(&union_bounds.max.y, &Real::from(2));
    assert_real_eq(&union_bounds.min.z, &Real::from(-2));
    assert_real_eq(&union_bounds.max.z, &Real::from(2));

    let intersection = hypermesh::boolean_exact_with_boundary_policy(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
        hypermesh::ExactBoundaryBooleanPolicy::PreserveSeparateShells,
    )
    .unwrap();
    assert!(intersection.mesh.triangles().is_empty());

    let difference = hypermesh::boolean_exact_with_boundary_policy(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
        hypermesh::ExactBoundaryBooleanPolicy::PreserveSeparateShells,
    )
    .unwrap();
    assert!(difference.mesh.facts().mesh.closed_manifold);
    assert!(!difference.mesh.triangles().is_empty());
}

#[test]
fn exact_closed_vertex_touch_contact_materializes_regularized_shortcuts() {
    let left = ExactMesh::from_i64_triangles(
        &[0, 0, 0, 2, 0, 0, 0, 2, 0, 0, 0, 2],
        &[0, 2, 1, 0, 1, 3, 1, 2, 3, 2, 0, 3],
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles(
        &[0, 0, 0, -2, 0, 0, 0, -2, 0, 0, 0, -2],
        &[0, 1, 2, 0, 3, 1, 1, 3, 2, 2, 3, 0],
    )
    .unwrap();

    let graph = build_intersection_graph(&left, &right).unwrap();
    assert!(!graph.has_unknowns());
    assert!(
        graph
            .face_pairs
            .iter()
            .any(|pair| { pair.relation == hypermesh::MeshFacePairRelation::Candidate })
    );
    assert!(graph.face_pairs.iter().all(|pair| {
        pair.relation != hypermesh::MeshFacePairRelation::Candidate
            || pair.events.iter().all(|event| {
                !matches!(
                    event,
                    IntersectionEvent::SegmentPlane {
                        relation: SegmentPlaneRelation::ProperCrossing
                            | SegmentPlaneRelation::ConstructionFailed
                            | SegmentPlaneRelation::Unknown,
                        ..
                    } | IntersectionEvent::Unknown
                )
            })
    }));

    let left_in_right =
        hypermesh::classify_mesh_vertices_against_closed_mesh_winding_report(&left, &right);
    let right_in_left =
        hypermesh::classify_mesh_vertices_against_closed_mesh_winding_report(&right, &left);
    left_in_right
        .validate_against_sources(&left, &right)
        .unwrap();
    right_in_left
        .validate_against_sources(&right, &left)
        .unwrap();
    assert!(
        left_in_right
            .vertices
            .iter()
            .all(|vertex| { vertex.relation != hypermesh::ClosedMeshWindingRelation::Inside })
    );
    assert!(
        right_in_left
            .vertices
            .iter()
            .all(|vertex| { vertex.relation != hypermesh::ClosedMeshWindingRelation::Inside })
    );
    assert!(
        left_in_right
            .vertices
            .iter()
            .any(|vertex| { vertex.relation == hypermesh::ClosedMeshWindingRelation::Boundary })
            || right_in_left.vertices.iter().any(|vertex| {
                vertex.relation == hypermesh::ClosedMeshWindingRelation::Boundary
            })
    );

    let boundary_report = hypermesh::certify_boundary_touching_report(&left, &right).unwrap();
    boundary_report.validate().unwrap();
    boundary_report
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        boundary_report.status,
        hypermesh::ExactBoundaryTouchingStatus::Certified
    );
    assert!(boundary_report.blocker.candidate_pairs > 0);
    assert_eq!(boundary_report.blocker.coplanar_overlapping_pairs, 0);

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    preflight.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedClosedBoundaryTouchingUnion
    );
    let union = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    union
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        union.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ClosedBoundaryTouchingUnion
        }
    );
    assert_eq!(
        union.mesh.triangles().len(),
        left.triangles().len() + right.triangles().len()
    );

    let intersection_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    intersection_preflight.validate().unwrap();
    intersection_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        intersection_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let intersection = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    intersection
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(intersection.mesh.triangles().is_empty());

    let difference_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    difference_preflight.validate().unwrap();
    difference_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let difference = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    difference
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(difference.mesh.vertices(), left.vertices());
    assert_eq!(difference.mesh.triangles(), left.triangles());

    let winding_report = hypermesh::certify_winding_readiness_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
    )
    .unwrap();
    winding_report.validate().unwrap();
    assert_eq!(
        winding_report.status,
        hypermesh::ExactWindingReadinessStatus::BoundaryPolicyRequired
    );

    let union = hypermesh::boolean_exact_with_boundary_policy(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
        hypermesh::ExactBoundaryBooleanPolicy::PreserveSeparateShells,
    )
    .unwrap();
    union.validate().unwrap();
    union.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        union.mesh.triangles().len(),
        left.triangles().len() + right.triangles().len()
    );
}

#[test]
fn exact_axis_aligned_face_touching_boxes_materialize_regularized_union_only() {
    let left = axis_aligned_box_i64([0, 0, 0], [2, 2, 2]);
    let right = axis_aligned_box_i64([2, 0, 0], [4, 2, 2]);

    let union_preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    union_preflight.validate().unwrap();
    union_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        union_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    assert!(union_preflight.blocker.is_none());

    let union = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    union.validate().unwrap();
    union
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        union.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(union.mesh.vertices().len(), 8);
    assert_eq!(union.mesh.triangles().len(), 12);
    assert!(union.mesh.facts().mesh.closed_manifold);
    let bounds = union.mesh.bounds().mesh.as_ref().unwrap();
    assert_real_eq(&bounds.min.x, &Real::from(0));
    assert_real_eq(&bounds.max.x, &Real::from(4));

    let difference_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    difference_preflight.validate().unwrap();
    difference_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    assert!(difference_preflight.blocker.is_none());
    let difference = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    difference.validate().unwrap();
    difference
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(difference.mesh.vertices().len(), 8);
    assert_eq!(difference.mesh.triangles().len(), 12);
    assert!(difference.mesh.facts().mesh.closed_manifold);
    let difference_bounds = difference.mesh.bounds().mesh.as_ref().unwrap();
    assert_real_eq(&difference_bounds.min.x, &Real::from(0));
    assert_real_eq(&difference_bounds.max.x, &Real::from(2));

    assert!(
        hypermesh::intersect_closed_convex_solids(&left, &right).is_none(),
        "zero-volume face contact must not be certified as a closed-convex solid intersection"
    );
    let intersection_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    intersection_preflight.validate().unwrap();
    intersection_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        intersection_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let intersection = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    intersection.validate().unwrap();
    intersection
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(intersection.mesh.triangles().is_empty());

    let edge_touching = axis_aligned_box_i64([2, 2, 0], [4, 4, 2]);
    assert!(hypermesh::intersect_closed_convex_solids(&left, &edge_touching).is_none());
    let edge_union_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &edge_touching,
        hypermesh::ExactBooleanOperation::Union,
    )
    .unwrap();
    edge_union_preflight.validate().unwrap();
    edge_union_preflight
        .validate_against_sources(&left, &edge_touching)
        .unwrap();
    assert_eq!(
        edge_union_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedClosedBoundaryTouchingUnion
    );
    let edge_union = hypermesh::boolean_exact(
        &left,
        &edge_touching,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    edge_union
        .validate_operation_against_sources(
            &left,
            &edge_touching,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        edge_union.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ClosedBoundaryTouchingUnion
        }
    );
    assert_eq!(
        edge_union.mesh.triangles().len(),
        left.triangles().len() + edge_touching.triangles().len()
    );
    let edge_intersection_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &edge_touching,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    edge_intersection_preflight.validate().unwrap();
    edge_intersection_preflight
        .validate_against_sources(&left, &edge_touching)
        .unwrap();
    assert_eq!(
        edge_intersection_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let edge_intersection = hypermesh::boolean_exact(
        &left,
        &edge_touching,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    edge_intersection
        .validate_operation_against_sources(
            &left,
            &edge_touching,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert!(edge_intersection.mesh.triangles().is_empty());

    let edge_difference_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &edge_touching,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    edge_difference_preflight.validate().unwrap();
    edge_difference_preflight
        .validate_against_sources(&left, &edge_touching)
        .unwrap();
    assert_eq!(
        edge_difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let edge_difference = hypermesh::boolean_exact(
        &left,
        &edge_touching,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    edge_difference
        .validate_operation_against_sources(
            &left,
            &edge_touching,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(edge_difference.mesh.vertices().len(), 8);
    assert_eq!(edge_difference.mesh.triangles().len(), 12);
    assert!(edge_difference.mesh.facts().mesh.closed_manifold);
    let edge_difference_bounds = edge_difference.mesh.bounds().mesh.as_ref().unwrap();
    assert_real_eq(&edge_difference_bounds.min.x, &Real::from(0));
    assert_real_eq(&edge_difference_bounds.max.x, &Real::from(2));
}

