#[test]
fn exact_axis_aligned_coplanar_volumetric_box_difference_materializes_two_components() {
    let left = axis_aligned_box_i64([0, 0, 0], [4, 2, 2]);
    let right = axis_aligned_box_i64([1, 0, 0], [3, 2, 2]);

    let preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    preflight.validate().unwrap();
    preflight.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let difference = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    difference.validate().unwrap();
    difference
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(difference.mesh.vertices().len(), 16);
    assert!(difference.mesh.triangles().len() >= 24);
    assert!(difference.mesh.facts().mesh.closed_manifold);
    let bounds = difference.mesh.bounds().mesh.as_ref().unwrap();
    assert_real_eq(&bounds.min.x, &Real::from(0));
    assert_real_eq(&bounds.max.x, &Real::from(4));

    let left_component_vertices = difference
        .mesh
        .vertices()
        .iter()
        .filter(|vertex| {
            compare_reals(&vertex.x, &Real::from(1)).value() != Some(Ordering::Greater)
        })
        .count();
    let right_component_vertices = difference
        .mesh
        .vertices()
        .iter()
        .filter(|vertex| compare_reals(&vertex.x, &Real::from(3)).value() != Some(Ordering::Less))
        .count();
    assert_eq!(left_component_vertices, 8);
    assert_eq!(right_component_vertices, 8);

    let mut relabeled = difference.clone();
    relabeled.kind = hypermesh::ExactBooleanResultKind::CertifiedShortcut {
        shortcut: hypermesh::ExactBooleanShortcutKind::ConvexContainment,
    };
    assert!(
        relabeled
            .validate_operation_against_sources(
                &left,
                &right,
                hypermesh::ExactBooleanOperation::Difference,
                ValidationPolicy::CLOSED,
                hypermesh::ExactBoundaryBooleanPolicy::Reject,
            )
            .is_err()
    );
}

