#[test]
fn exact_affine_coplanar_volumetric_boxes_materialize_cell_complexes() {
    let origin = [0, 0, 0];
    let basis_u = [2, 1, 0];
    let basis_v = [-1, 2, 0];
    let basis_w = [0, 1, 2];
    let left = affine_box_i64([0, 0, 0], [2, 2, 2], origin, basis_u, basis_v, basis_w);
    let right = affine_box_i64([1, 1, 0], [3, 3, 2], origin, basis_u, basis_v, basis_w);

    let union_arrangement = hypermesh::affine_box::materialize_affine_box_union(
        &left,
        &right,
        ValidationPolicy::CLOSED,
    )
    .unwrap()
    .expect("sheared box union should materialize through retained affine cells");
    union_arrangement.validate().unwrap();
    union_arrangement
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        union_arrangement.operation,
        hypermesh::affine_box::AffineBoxOperation::Union
    );
    assert!(union_arrangement.mesh.facts().mesh.closed_manifold);
    assert!(union_arrangement.mesh.triangles().len() > left.triangles().len());

    let mut relabeled = union_arrangement.clone();
    relabeled.operation = hypermesh::affine_box::AffineBoxOperation::Difference;
    assert!(relabeled.validate_against_sources(&left, &right).is_err());

    let union_preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    union_preflight.validate().unwrap();
    union_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        union_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    assert!(union_preflight.blocker.is_none());

    let union = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    union
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        union.kind,
        hypermesh::ExactBooleanResultKind::ArrangementCellComplexMaterialized {
            operation: hypermesh::ExactBooleanOperation::Union
        }
    );

    let intersection_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    intersection_preflight.validate().unwrap();
    intersection_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        intersection_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let intersection = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    intersection
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::ArrangementCellComplexMaterialized {
            operation: hypermesh::ExactBooleanOperation::Intersection
        }
    );
    assert!(intersection.mesh.facts().mesh.closed_manifold);
    assert!(intersection.mesh.vertices().len() >= 8);
    assert!(intersection.mesh.triangles().len() >= 12);

    let difference_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    difference_preflight.validate().unwrap();
    difference_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let difference = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    difference
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::ArrangementCellComplexMaterialized {
            operation: hypermesh::ExactBooleanOperation::Difference
        }
    );

    let point_touch = affine_box_i64([2, 2, 2], [3, 3, 3], origin, basis_u, basis_v, basis_w);
    assert!(
        hypermesh::affine_box::materialize_affine_box_union(
            &left,
            &point_touch,
            ValidationPolicy::CLOSED
        )
        .unwrap()
        .is_none()
    );
}

#[test]
fn exact_affine_orthogonal_solid_cell_complex_reenters_boolean() {
    let origin = [0, 0, 0];
    let basis_u = [2, 1, 0];
    let basis_v = [-1, 2, 0];
    let basis_w = [0, 1, 2];
    let left = affine_box_i64([0, 0, 0], [2, 2, 2], origin, basis_u, basis_v, basis_w);
    let right = affine_box_i64([1, 1, 0], [3, 3, 2], origin, basis_u, basis_v, basis_w);
    let complex = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap()
    .mesh;
    assert!(complex.facts().mesh.closed_manifold);
    assert!(complex.triangles().len() > left.triangles().len());

    let cutter = affine_box_i64([2, 0, 0], [3, 2, 2], origin, basis_u, basis_v, basis_w);
    let union_arrangement = hypermesh::affine_solid::materialize_affine_orthogonal_solid_union(
        &complex,
        &cutter,
        ValidationPolicy::CLOSED,
    )
    .unwrap()
    .expect("affine orthogonal solid union should replay from retained cell output");
    union_arrangement.validate().unwrap();
    union_arrangement
        .validate_against_sources(&complex, &cutter)
        .unwrap();
    assert_eq!(
        union_arrangement.operation,
        hypermesh::affine_solid::AffineOrthogonalSolidOperation::Union
    );

    let union_preflight = hypermesh::preflight_boolean_exact(
        &complex,
        &cutter,
        hypermesh::ExactBooleanOperation::Union,
    )
    .unwrap();
    union_preflight.validate().unwrap();
    union_preflight
        .validate_against_sources(&complex, &cutter)
        .unwrap();
    assert_eq!(
        union_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let union = hypermesh::boolean_exact(
        &complex,
        &cutter,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    union
        .validate_operation_against_sources(
            &complex,
            &cutter,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        union.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(union.mesh.facts().mesh.closed_manifold);

    let intersection_preflight = hypermesh::preflight_boolean_exact(
        &complex,
        &cutter,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    intersection_preflight.validate().unwrap();
    intersection_preflight
        .validate_against_sources(&complex, &cutter)
        .unwrap();
    assert_eq!(
        intersection_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let intersection = hypermesh::boolean_exact(
        &complex,
        &cutter,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    intersection
        .validate_operation_against_sources(
            &complex,
            &cutter,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );

    let difference_preflight = hypermesh::preflight_boolean_exact(
        &complex,
        &cutter,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    difference_preflight.validate().unwrap();
    difference_preflight
        .validate_against_sources(&complex, &cutter)
        .unwrap();
    assert_eq!(
        difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let difference = hypermesh::boolean_exact(
        &complex,
        &cutter,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    difference
        .validate_operation_against_sources(
            &complex,
            &cutter,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(difference.mesh.facts().mesh.closed_manifold);

    let mut stale = union_arrangement.clone();
    stale.operation = hypermesh::affine_solid::AffineOrthogonalSolidOperation::Difference;
    assert!(stale.validate_against_sources(&complex, &cutter).is_err());
}

#[test]
fn exact_affine_orthogonal_solid_cell_complexes_discover_shared_frame() {
    let origin = [0, 0, 0];
    let basis_u = [2, 1, 0];
    let basis_v = [-1, 2, 0];
    let basis_w = [0, 1, 2];
    let a0 = affine_box_i64([0, 0, 0], [2, 2, 2], origin, basis_u, basis_v, basis_w);
    let a1 = affine_box_i64([1, 1, 0], [3, 3, 2], origin, basis_u, basis_v, basis_w);
    let b0 = affine_box_i64([2, 0, 0], [4, 2, 2], origin, basis_u, basis_v, basis_w);
    let b1 = affine_box_i64([3, 1, 0], [5, 3, 2], origin, basis_u, basis_v, basis_w);
    let first = hypermesh::boolean_exact(
        &a0,
        &a1,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap()
    .mesh;
    let second = hypermesh::boolean_exact(
        &b0,
        &b1,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap()
    .mesh;
    assert!(first.triangles().len() > a0.triangles().len());
    assert!(second.triangles().len() > b0.triangles().len());

    let union_preflight = hypermesh::preflight_boolean_exact(
        &first,
        &second,
        hypermesh::ExactBooleanOperation::Union,
    )
    .unwrap();
    union_preflight.validate().unwrap();
    union_preflight
        .validate_against_sources(&first, &second)
        .unwrap();
    assert_eq!(
        union_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let intersection = hypermesh::boolean_exact(
        &first,
        &second,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    intersection
        .validate_operation_against_sources(
            &first,
            &second,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(intersection.mesh.facts().mesh.closed_manifold);

    let difference = hypermesh::boolean_exact(
        &first,
        &second,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    difference
        .validate_operation_against_sources(
            &first,
            &second,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(difference.mesh.facts().mesh.closed_manifold);

    let mut stale = union_preflight.clone();
    stale.support = hypermesh::ExactBooleanSupport::CertifiedConvexContainment;
    assert!(stale.validate_against_sources(&first, &second).is_err());
}

#[test]
fn exact_affine_orthogonal_solid_intersection_materializes_empty_cavity_cell_set() {
    let origin = [0, 0, 0];
    let basis_u = [2, 1, 0];
    let basis_v = [-1, 2, 0];
    let basis_w = [0, 1, 2];
    let outer = affine_box_i64([0, 0, 0], [8, 8, 8], origin, basis_u, basis_v, basis_w);
    let cavity = affine_box_i64([2, 2, 2], [6, 6, 6], origin, basis_u, basis_v, basis_w);
    let hollow = hypermesh::boolean_exact(
        &outer,
        &cavity,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap()
    .mesh;
    assert!(hollow.facts().mesh.closed_manifold);

    let floating = affine_box_i64([3, 3, 3], [5, 5, 5], origin, basis_u, basis_v, basis_w);
    let preflight = hypermesh::preflight_boolean_exact(
        &hollow,
        &floating,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    preflight.validate().unwrap();
    preflight
        .validate_against_sources(&hollow, &floating)
        .unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let intersection = hypermesh::boolean_exact(
        &hollow,
        &floating,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    intersection
        .validate_operation_against_sources(
            &hollow,
            &floating,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(intersection.mesh.vertices().is_empty());
    assert!(intersection.mesh.triangles().is_empty());
}

