#[test]
fn exact_mixed_coplanar_volumetric_overlap_materializes_from_face_cells() {
    let left = ExactMesh::from_i64_triangles(
        &[
            0, 0, 0, 2, 0, 0, 2, 2, 0, 0, 2, 0, 0, 0, 2, 2, 0, 2, 2, 2, 2, 0, 2, 2,
        ],
        &[
            0, 2, 1, 0, 3, 2, 4, 5, 6, 4, 6, 7, 0, 1, 5, 0, 5, 4, 1, 2, 6, 1, 6, 5, 2, 3, 7, 2, 7,
            6, 3, 0, 4, 3, 4, 7,
        ],
    )
    .unwrap();
    let right = top_subdivided_axis_aligned_box_i64([1, 1, 0], [3, 3, 2]);

    let graph = build_intersection_graph(&left, &right).unwrap();
    assert!(!graph.has_unknowns());
    assert!(
        graph
            .face_pairs
            .iter()
            .any(|pair| { pair.relation == hypermesh::MeshFacePairRelation::CoplanarOverlapping })
    );
    assert!(graph.face_pairs.iter().any(|pair| {
        pair.relation == hypermesh::MeshFacePairRelation::Candidate
            && pair.events.iter().any(|event| {
                matches!(
                    event,
                    IntersectionEvent::SegmentPlane {
                        relation: SegmentPlaneRelation::ProperCrossing,
                        ..
                    }
                )
            })
    }));

    let boundary_report = hypermesh::certify_boundary_touching_report(&left, &right).unwrap();
    boundary_report.validate().unwrap();
    assert_eq!(
        boundary_report.status,
        hypermesh::ExactBoundaryTouchingStatus::NotBoundaryOnly
    );

    for (operation, support, shortcut) in [
        (
            hypermesh::ExactBooleanOperation::Union,
            hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex,
            hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex,
        ),
        (
            hypermesh::ExactBooleanOperation::Intersection,
            hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex,
            hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex,
        ),
        (
            hypermesh::ExactBooleanOperation::Difference,
            hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex,
            hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex,
        ),
    ] {
        let preflight = hypermesh::preflight_boolean_exact(&left, &right, operation).unwrap();
        preflight.validate().unwrap();
        preflight.validate_against_sources(&left, &right).unwrap();
        assert_eq!(preflight.support, support);
        assert!(preflight.blocker.is_none());
        assert_eq!(preflight.region_count, 0);

        let winding_report =
            hypermesh::certify_winding_readiness_report(&left, &right, operation).unwrap();
        winding_report.validate().unwrap();
        winding_report
            .validate_against_sources(&left, &right)
            .unwrap();
        assert_eq!(
            winding_report.status,
            hypermesh::ExactWindingReadinessStatus::Ready
        );
        assert!(winding_report.region_count > 0);

        let result =
            hypermesh::boolean_exact(&left, &right, operation, ValidationPolicy::CLOSED).unwrap();
        result.validate().unwrap();
        result
            .validate_operation_against_sources(
                &left,
                &right,
                operation,
                ValidationPolicy::CLOSED,
                hypermesh::ExactBoundaryBooleanPolicy::Reject,
            )
            .unwrap();
        let expected_kind = if matches!(operation, hypermesh::ExactBooleanOperation::Intersection) {
            hypermesh::ExactBooleanResultKind::CertifiedShortcut { shortcut }
        } else {
            hypermesh::ExactBooleanResultKind::ArrangementCellComplexMaterialized { operation }
        };
        assert_eq!(result.kind, expected_kind);
        assert!(result.mesh.facts().mesh.closed_manifold);
    }
}

#[test]
fn exact_full_face_adjacent_tetrahedra_union_deletes_internal_face() {
    let left = tetrahedron_i64([0, 0, 0], [4, 0, 0], [0, 4, 0], [0, 0, 4]);
    let right = tetrahedron_i64([0, 0, 0], [0, 4, 0], [4, 0, 0], [0, 0, -4]);

    let graph = build_intersection_graph(&left, &right).unwrap();
    graph.validate_against_meshes(&left, &right).unwrap();
    assert!(graph.face_pairs.iter().any(|pair| {
        pair.relation == hypermesh::MeshFacePairRelation::CoplanarOverlapping
            && pair.left_face == 0
            && pair.right_face == 0
    }));

    let boundary = hypermesh::certify_boundary_touching_report(&left, &right).unwrap();
    boundary.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        boundary.status,
        hypermesh::ExactBoundaryTouchingStatus::Certified
    );

    let union = hypermesh::adjacent::materialize_full_face_adjacent_union(
        &left,
        &right,
        ValidationPolicy::CLOSED,
    )
    .expect("opposite-oriented shared faces should merge as an exact closed union");
    union.validate().unwrap();
    union.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        union.shared_faces,
        vec![hypermesh::adjacent::FullFaceAdjacentFacePair {
            left_face: 0,
            right_face: 0,
        }]
    );
    assert_eq!(union.mesh.vertices().len(), 5);
    assert_eq!(union.mesh.triangles().len(), 6);
    assert!(union.mesh.facts().mesh.closed_manifold);

    let mut stale_faces = union.clone();
    stale_faces.shared_faces[0].right_face = 1;
    assert_eq!(
        stale_faces
            .validate_against_sources(&left, &right)
            .unwrap_err(),
        hypermesh::adjacent::FullFaceAdjacentUnionError::SourceReplayMismatch
    );
    let mut stale_mesh = union.clone();
    stale_mesh.mesh = left.clone();
    assert_eq!(
        stale_mesh
            .validate_against_sources(&left, &right)
            .unwrap_err(),
        hypermesh::adjacent::FullFaceAdjacentUnionError::SourceReplayMismatch
    );

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    preflight.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    result.validate().unwrap();
    result
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(result.mesh.vertices().len(), union.mesh.vertices().len());
    assert_eq!(result.mesh.triangles().len(), union.mesh.triangles().len());
    assert!(result.mesh.facts().mesh.closed_manifold);

    let intersection_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    intersection_preflight.validate().unwrap();
    intersection_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        intersection_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let intersection_attempt = hypermesh::exact_arrangement_boolean_attempt_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        hypermesh::ExactRegularizationPolicy::REGULARIZED_SOLID,
    )
    .unwrap();
    assert_eq!(
        intersection_attempt.stage,
        hypermesh::ExactArrangementBooleanStage::Materialized
    );
    assert_eq!(
        intersection_attempt.materialized_shortcut,
        Some(hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex)
    );
    assert!(intersection_attempt.decline.is_none());
    assert_eq!(intersection_attempt.output_triangles, 0);
    let intersection = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    intersection.validate().unwrap();
    intersection
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(intersection.mesh.triangles().is_empty());
    assert_eq!(
        intersection
            .validate_operation_against_sources(
                &left,
                &right,
                hypermesh::ExactBooleanOperation::Difference,
                ValidationPolicy::CLOSED,
                hypermesh::ExactBoundaryBooleanPolicy::Reject,
            )
            .unwrap_err(),
        hypermesh::ExactReportValidationError::SourceReplayMismatch
    );

    let difference_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    difference_preflight.validate().unwrap();
    difference_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let difference_attempt = hypermesh::exact_arrangement_boolean_attempt_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        hypermesh::ExactRegularizationPolicy::REGULARIZED_SOLID,
    )
    .unwrap();
    assert_eq!(
        difference_attempt.stage,
        hypermesh::ExactArrangementBooleanStage::Materialized
    );
    assert_eq!(
        difference_attempt.materialized_shortcut,
        Some(hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex)
    );
    assert!(difference_attempt.decline.is_none());
    assert_eq!(difference_attempt.output_triangles, left.triangles().len());
    let difference = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    difference.validate().unwrap();
    difference
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(difference.mesh.vertices().len(), left.vertices().len());
    assert_eq!(difference.mesh.triangles().len(), left.triangles().len());
    assert!(difference.mesh.facts().mesh.closed_manifold);

    let same_orientation = tetrahedron_i64([0, 0, 0], [4, 0, 0], [0, 4, 0], [0, 0, -4]);
    assert!(
        hypermesh::adjacent::materialize_full_face_adjacent_union(
            &left,
            &same_orientation,
            ValidationPolicy::CLOSED,
        )
        .is_none()
    );

    let same_side_overlap = tetrahedron_i64([0, 0, 0], [0, 4, 0], [4, 0, 0], [0, 0, 2]);
    assert!(
        hypermesh::adjacent::materialize_full_face_adjacent_union(
            &left,
            &same_side_overlap,
            ValidationPolicy::CLOSED,
        )
        .is_none()
    );
}

#[test]
fn exact_full_face_adjacent_fan_patch_union_deletes_nonconforming_internal_faces() {
    let left = tetrahedron_i64([0, 0, 0], [4, 0, 0], [0, 4, 0], [0, 0, 4]);
    let right = base_fan_tetrahedron_i64([0, 0, 0], [4, 0, 0], [0, 4, 0], [1, 1, 0], [0, 0, -4]);

    let graph = build_intersection_graph(&left, &right).unwrap();
    graph.validate_against_meshes(&left, &right).unwrap();
    assert!(
        graph
            .face_pairs
            .iter()
            .filter(|pair| {
                pair.left_face == 0
                    && pair.relation == hypermesh::MeshFacePairRelation::CoplanarOverlapping
            })
            .count()
            >= 3
    );

    let union = hypermesh::adjacent::materialize_full_face_adjacent_union(
        &left,
        &right,
        ValidationPolicy::CLOSED,
    )
    .expect("opposite-oriented fan patch should merge as an exact closed union");
    union.validate().unwrap();
    union.validate_against_sources(&left, &right).unwrap();
    assert!(union.shared_faces.is_empty());
    assert_eq!(
        union.shared_patches,
        vec![hypermesh::adjacent::FullFaceAdjacentPatch {
            left_faces: vec![0],
            right_faces: vec![0, 1, 2],
        }]
    );
    assert_eq!(union.mesh.vertices().len(), 5);
    assert_eq!(union.mesh.triangles().len(), 6);
    assert!(union.mesh.facts().mesh.closed_manifold);

    let mut stale_patch = union.clone();
    stale_patch.shared_patches[0].right_faces.pop();
    assert_eq!(
        stale_patch
            .validate_against_sources(&left, &right)
            .unwrap_err(),
        hypermesh::adjacent::FullFaceAdjacentUnionError::SourceReplayMismatch
    );

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    preflight.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    result
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(result.mesh.facts().mesh.closed_manifold);
    assert!(result.mesh.triangles().len() >= union.mesh.triangles().len());

    let intersection_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    intersection_preflight.validate().unwrap();
    intersection_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        intersection_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let intersection = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    intersection
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(intersection.mesh.triangles().is_empty());

    let difference_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    difference_preflight.validate().unwrap();
    difference_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let difference = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    difference
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(difference.mesh.facts().mesh.closed_manifold);
    assert!(!difference.mesh.triangles().is_empty());

    let reverse_difference = hypermesh::boolean_exact(
        &right,
        &left,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    reverse_difference
        .validate_operation_against_sources(
            &right,
            &left,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        reverse_difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(reverse_difference.mesh.vertices(), right.vertices());
    assert_eq!(reverse_difference.mesh.triangles(), right.triangles());

    let same_side_overlap =
        base_fan_tetrahedron_i64([0, 0, 0], [4, 0, 0], [0, 4, 0], [1, 1, 0], [0, 0, 2]);
    assert!(
        hypermesh::adjacent::materialize_full_face_adjacent_union(
            &left,
            &same_side_overlap,
            ValidationPolicy::CLOSED,
        )
        .is_none()
    );
}

