#[test]
fn exact_contained_face_adjacent_tetrahedra_union_replaces_containing_face_with_hole() {
    let left = tetrahedron_i64([0, 0, 0], [6, 0, 0], [0, 6, 0], [0, 0, 6]);
    let right = tetrahedron_i64([1, 1, 0], [1, 2, 0], [2, 1, 0], [1, 1, -3]);

    let graph = build_intersection_graph(&left, &right).unwrap();
    graph.validate_against_meshes(&left, &right).unwrap();
    assert!(graph.face_pairs.iter().any(|pair| {
        pair.left_face == 0
            && pair.right_face == 0
            && pair.relation == hypermesh::MeshFacePairRelation::CoplanarOverlapping
    }));

    let boundary = hypermesh::certify_boundary_touching_report(&left, &right).unwrap();
    boundary.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        boundary.status,
        hypermesh::ExactBoundaryTouchingStatus::Certified
    );

    let union = hypermesh::contained_adjacent::materialize_contained_face_adjacent_union(
        &left,
        &right,
        ValidationPolicy::CLOSED,
    )
    .expect("strictly contained opposite-oriented face should replay as a holed union");
    union.validate().unwrap();
    union.validate_against_sources(&left, &right).unwrap();
    assert_eq!(union.containing_side, MeshSide::Left);
    assert_eq!(union.containing_face, 0);
    assert_eq!(union.contained_face, 0);
    assert_eq!(union.contained_faces, vec![0]);
    assert_eq!(union.containing_faces, vec![0]);
    assert!(union.mesh.facts().mesh.closed_manifold);
    assert!(union.mesh.vertices().len() >= left.vertices().len() + right.vertices().len());
    assert!(union.mesh.triangles().len() > left.triangles().len() + right.triangles().len());

    let mut stale_face = union.clone();
    stale_face.contained_face = 1;
    assert_eq!(
        stale_face
            .validate_against_sources(&left, &right)
            .unwrap_err(),
        hypermesh::contained_adjacent::ContainedFaceAdjacentUnionError::SourceReplayMismatch
    );
    let mut stale_mesh = union.clone();
    stale_mesh.mesh = left.clone();
    assert_eq!(
        stale_mesh
            .validate_against_sources(&left, &right)
            .unwrap_err(),
        hypermesh::contained_adjacent::ContainedFaceAdjacentUnionError::SourceReplayMismatch
    );

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    preflight.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let union_attempt = hypermesh::exact_arrangement_boolean_attempt_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        hypermesh::ExactRegularizationPolicy::REGULARIZED_SOLID,
    )
    .unwrap();
    assert_eq!(
        union_attempt.stage,
        hypermesh::ExactArrangementBooleanStage::Materialized
    );
    assert_eq!(
        union_attempt.materialized_shortcut,
        Some(hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex)
    );
    assert!(union_attempt.decline.is_none());

    let result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    result.validate().unwrap();
    result
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_exact_mesh_same_vertex_set_and_face_count(&result.mesh, &union.mesh);

    let intersection_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    intersection_preflight.validate().unwrap();
    intersection_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        intersection_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let intersection_attempt = hypermesh::exact_arrangement_boolean_attempt_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        hypermesh::ExactRegularizationPolicy::REGULARIZED_SOLID,
    )
    .unwrap();
    assert_eq!(
        intersection_attempt.stage,
        hypermesh::ExactArrangementBooleanStage::Materialized
    );
    assert_eq!(
        intersection_attempt.materialized_shortcut,
        Some(hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex)
    );
    assert!(intersection_attempt.decline.is_none());
    assert_eq!(intersection_attempt.output_triangles, 0);
    let intersection = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    intersection
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(intersection.mesh.vertices().is_empty());
    assert!(intersection.mesh.triangles().is_empty());

    let difference_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    difference_preflight.validate().unwrap();
    difference_preflight
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let difference = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    difference
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(difference.mesh.vertices(), left.vertices());
    assert_eq!(difference.mesh.triangles(), left.triangles());

    let reverse_difference_preflight = hypermesh::preflight_boolean_exact(
        &right,
        &left,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    reverse_difference_preflight.validate().unwrap();
    reverse_difference_preflight
        .validate_against_sources(&right, &left)
        .unwrap();
    assert_eq!(
        reverse_difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let reverse_difference = hypermesh::boolean_exact(
        &right,
        &left,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    reverse_difference
        .validate_operation_against_sources(
            &right,
            &left,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        reverse_difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_eq!(reverse_difference.mesh.vertices(), right.vertices());
    assert_eq!(reverse_difference.mesh.triangles(), right.triangles());

    let same_side_inner = tetrahedron_i64([1, 1, 0], [2, 1, 0], [1, 2, 0], [1, 1, 3]);
    assert!(
        hypermesh::contained_adjacent::materialize_contained_face_adjacent_union(
            &left,
            &same_side_inner,
            ValidationPolicy::CLOSED,
        )
        .is_none()
    );
}

#[test]
fn exact_contained_face_adjacent_multi_tetrahedra_union_replaces_containing_face_with_holes() {
    let left_a = tetrahedron_i64([0, 0, 0], [8, 0, 0], [0, 8, 0], [0, 0, 8]);
    let left_b = tetrahedron_i64([20, 0, 0], [28, 0, 0], [20, 8, 0], [20, 0, 8]);
    let left = combine_exact_meshes(
        &[left_a, left_b],
        "exact contained-face adjacent two-container fixture",
    );
    let right_a = tetrahedron_i64([1, 1, 0], [1, 2, 0], [2, 1, 0], [1, 1, -3]);
    let right_b = tetrahedron_i64([21, 1, 0], [21, 2, 0], [22, 1, 0], [21, 1, -3]);
    let right = combine_exact_meshes(
        &[right_a, right_b],
        "exact contained-face adjacent two-cap fixture",
    );

    let graph = build_intersection_graph(&left, &right).unwrap();
    graph.validate_against_meshes(&left, &right).unwrap();
    assert!(graph.face_pairs.iter().any(|pair| {
        pair.left_face == 0
            && pair.right_face == 0
            && pair.relation == hypermesh::MeshFacePairRelation::CoplanarOverlapping
    }));
    assert!(graph.face_pairs.iter().any(|pair| {
        pair.left_face == 4
            && pair.right_face == 4
            && pair.relation == hypermesh::MeshFacePairRelation::CoplanarOverlapping
    }));

    let union = hypermesh::contained_adjacent::materialize_contained_face_adjacent_union(
        &left,
        &right,
        ValidationPolicy::CLOSED,
    )
    .expect("multiple disjoint contained caps should replay as a multi-holed adjacent union");
    union.validate().unwrap();
    union.validate_against_sources(&left, &right).unwrap();
    assert_eq!(union.containing_side, MeshSide::Left);
    assert_eq!(union.containing_face, 0);
    assert_eq!(union.contained_face, 0);
    assert_eq!(union.contained_faces, vec![0, 4]);
    assert_eq!(union.containing_faces, vec![0, 4]);
    assert!(union.mesh.facts().mesh.closed_manifold);
    assert!(union.mesh.triangles().len() > left.triangles().len() + right.triangles().len());

    let mut stale = union.clone();
    stale.contained_faces.pop();
    assert_eq!(
        stale.validate_against_sources(&left, &right).unwrap_err(),
        hypermesh::contained_adjacent::ContainedFaceAdjacentUnionError::SourceReplayMismatch
    );

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    preflight.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    result
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert_exact_mesh_same_vertex_set_and_face_count(&result.mesh, &union.mesh);

    let single_left = tetrahedron_i64([0, 0, 0], [8, 0, 0], [0, 8, 0], [0, 0, 8]);
    let same_face_right = combine_exact_meshes(
        &[
            tetrahedron_i64([1, 1, 0], [1, 2, 0], [2, 1, 0], [1, 1, -3]),
            tetrahedron_i64([2, 4, 0], [2, 5, 0], [3, 4, 0], [2, 4, -3]),
        ],
        "same containing face multi-hole contained adjacency",
    );
    let same_face_graph = build_intersection_graph(&single_left, &same_face_right).unwrap();
    same_face_graph
        .validate_against_meshes(&single_left, &same_face_right)
        .unwrap();
    assert!(same_face_graph.face_pairs.iter().any(|pair| {
        pair.left_face == 0
            && pair.right_face == 0
            && pair.relation == hypermesh::MeshFacePairRelation::CoplanarOverlapping
    }));
    assert!(same_face_graph.face_pairs.iter().any(|pair| {
        pair.left_face == 0
            && pair.right_face == 4
            && pair.relation == hypermesh::MeshFacePairRelation::CoplanarOverlapping
    }));

    let same_face_union = hypermesh::contained_adjacent::materialize_contained_face_adjacent_union(
        &single_left,
        &same_face_right,
        ValidationPolicy::CLOSED,
    )
    .expect(
        "one containing face with two contained caps should materialize as one multi-hole patch",
    );
    same_face_union.validate().unwrap();
    same_face_union
        .validate_against_sources(&single_left, &same_face_right)
        .unwrap();
    assert_eq!(same_face_union.containing_side, MeshSide::Left);
    assert_eq!(same_face_union.containing_face, 0);
    assert_eq!(same_face_union.contained_face, 0);
    assert_eq!(same_face_union.contained_faces, vec![0, 4]);
    assert_eq!(same_face_union.containing_faces, vec![0]);
    assert!(same_face_union.mesh.facts().mesh.closed_manifold);

    let same_face_preflight = hypermesh::preflight_boolean_exact(
        &single_left,
        &same_face_right,
        hypermesh::ExactBooleanOperation::Union,
    )
    .unwrap();
    same_face_preflight.validate().unwrap();
    same_face_preflight
        .validate_against_sources(&single_left, &same_face_right)
        .unwrap();
    assert_eq!(
        same_face_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let same_face_result = hypermesh::boolean_exact(
        &single_left,
        &same_face_right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    same_face_result
        .validate_operation_against_sources(
            &single_left,
            &same_face_right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(same_face_result.mesh, same_face_union.mesh);
}

