#[test]
fn exact_named_booleans_handle_structurally_identical_meshes() {
    let mesh = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 1, 0, 0, 0, 1, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    let union = hypermesh::boolean_exact(
        &mesh,
        &mesh,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert_eq!(union.mesh.triangles(), mesh.triangles());
    assert_eq!(union.mesh.vertices(), mesh.vertices());

    let intersection = hypermesh::boolean_exact(
        &mesh,
        &mesh,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert_eq!(intersection.mesh.triangles(), mesh.triangles());
    assert_eq!(intersection.mesh.vertices(), mesh.vertices());

    let difference = hypermesh::boolean_exact(
        &mesh,
        &mesh,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert!(difference.mesh.triangles().is_empty());
    assert!(difference.mesh.vertices().is_empty());

    let preflight = hypermesh::preflight_boolean_exact(
        &mesh,
        &mesh,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedIdentical
    );
    assert_eq!(preflight.region_count, 0);
}

#[test]
fn exact_named_booleans_handle_reversed_same_indexed_surface() {
    let vertices = [
        0, 0, 0, //
        1, 0, 0, //
        0, 1, 0, //
        0, 0, 1,
    ];
    let mesh =
        ExactMesh::from_i64_triangles(&vertices, &[0, 2, 1, 0, 1, 3, 1, 2, 3, 2, 0, 3]).unwrap();
    let reversed =
        ExactMesh::from_i64_triangles(&vertices, &[0, 1, 2, 0, 3, 1, 1, 3, 2, 2, 3, 0]).unwrap();

    let preflight = hypermesh::preflight_boolean_exact(
        &mesh,
        &reversed,
        hypermesh::ExactBooleanOperation::Union,
    )
    .unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedSameSurface
    );
    assert_eq!(preflight.retained_events, 0);
    let report = hypermesh::certify_same_surface_report(&mesh, &reversed);
    report.validate().unwrap();
    assert!(report.is_certified());
    assert_eq!(report.left_to_right, vec![0, 1, 2, 3]);
    assert_eq!(report.right_to_left, vec![0, 1, 2, 3]);
    assert_eq!(report.left_triangles, report.right_triangles);
    assert!(report.all_proof_producing());

    let union = hypermesh::boolean_exact(
        &mesh,
        &reversed,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    assert_eq!(union.mesh.triangles(), mesh.triangles());

    let intersection = hypermesh::boolean_exact(
        &mesh,
        &reversed,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    assert_eq!(intersection.mesh.triangles(), mesh.triangles());

    let difference = hypermesh::boolean_exact(
        &mesh,
        &reversed,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    assert!(difference.mesh.triangles().is_empty());
}

#[test]
fn exact_named_booleans_handle_reindexed_same_surface() {
    let left_vertices = [
        0, 0, 0, //
        1, 0, 0, //
        0, 1, 0, //
        0, 0, 1,
    ];
    let right_vertices = [
        0, 0, 1, //
        0, 0, 0, //
        0, 1, 0, //
        1, 0, 0,
    ];
    let left = ExactMesh::from_i64_triangles(&left_vertices, &[0, 2, 1, 0, 1, 3, 1, 2, 3, 2, 0, 3])
        .unwrap();
    let right =
        ExactMesh::from_i64_triangles(&right_vertices, &[1, 3, 2, 1, 0, 3, 3, 0, 2, 2, 0, 1])
            .unwrap();

    let preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedSameSurface
    );
    let report = hypermesh::certify_same_surface_report(&left, &right);
    report.validate().unwrap();
    report.validate_against_sources(&left, &right).unwrap();
    assert!(report.is_certified());
    assert_eq!(report.left_to_right, vec![1, 3, 2, 0]);
    assert_eq!(report.right_to_left, vec![3, 0, 2, 1]);
    assert_eq!(report.left_triangles, report.right_triangles);
    assert!(report.all_proof_producing());
    assert_eq!(
        report.validate_against_sources(&right, &left).unwrap_err(),
        hypermesh::ExactReportValidationError::SourceReplayMismatch
    );

    let intersection = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    assert_eq!(intersection.mesh.vertices(), left.vertices());
    assert_eq!(intersection.mesh.triangles(), left.triangles());
}

#[test]
fn exact_named_booleans_handle_coplanar_convex_surface_retriangulation() {
    let vertices = &[0, 0, 0, 2, 0, 0, 2, 2, 0, 0, 2, 0];
    let left = ExactMesh::from_i64_triangles_with_policy(
        vertices,
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        vertices,
        &[0, 1, 3, 1, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    assert!(!hypermesh::certify_same_surface_report(&left, &right).is_certified());
    let certificate = surface::certify_coplanar_convex_surface_equivalence(&left, &right)
        .expect("same square with opposite diagonals should certify by exact hull/area");
    certificate.validate().unwrap();
    certificate.validate_against_sources(&left, &right).unwrap();
    let shifted = ExactMesh::from_i64_triangles_with_policy(
        &[10, 0, 0, 12, 0, 0, 12, 2, 0, 10, 2, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert!(
        certificate
            .validate_against_sources(&left, &shifted)
            .is_err()
    );
    assert_eq!(certificate.polygon.len(), 4);
    let mut reversed_hull = certificate.clone();
    reversed_hull.polygon.reverse();
    assert!(reversed_hull.validate().is_err());
    let mut repeated_hull_point = certificate.clone();
    repeated_hull_point.polygon[1] = repeated_hull_point.polygon[0].clone();
    assert!(repeated_hull_point.validate().is_err());
    let mut nonconvex_hull = certificate.clone();
    nonconvex_hull.polygon = vec![p3(0, 0, 0), p3(2, 0, 0), p3(1, 1, 0), p3(0, 2, 0)];
    assert!(nonconvex_hull.validate().is_err());
    let report = surface::certify_coplanar_convex_surface_report(&left, &right);
    report.validate().unwrap();
    report.validate_against_sources(&left, &right).unwrap();
    assert!(report.is_certified());
    assert_eq!(
        report.status,
        surface::CoplanarConvexSurfaceReportStatus::Equivalent
    );
    assert!(report.equivalence.is_some());
    assert!(report.containment.is_none());
    let mut stale_report = report.clone();
    stale_report
        .equivalence
        .as_mut()
        .unwrap()
        .polygon
        .rotate_left(1);
    assert_eq!(
        stale_report
            .validate_against_sources(&left, &right)
            .unwrap_err(),
        surface::CoplanarConvexSurfaceReportError::SourceReplayMismatch
    );

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    assert!(preflight.blocker.is_none());

    let union = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    union.validate().unwrap();
    assert_eq!(
        union.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    union
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert!(exact_mesh_vertex_sets_equal(&union.mesh, &left));

    let difference = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert!(difference.mesh.triangles().is_empty());
}

#[test]
fn exact_named_booleans_handle_coplanar_convex_surface_containment() {
    let outer = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 4, 0, 0, 4, 4, 0, 0, 4, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let inner = ExactMesh::from_i64_triangles_with_policy(
        &[1, 1, 0, 2, 1, 0, 2, 2, 0, 1, 2, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    let certificate = surface::certify_coplanar_convex_surface_containment(&outer, &inner)
        .expect("inner square should certify inside outer square");
    certificate.validate().unwrap();
    certificate
        .validate_against_sources(&outer, &inner)
        .unwrap();
    assert!(
        certificate
            .validate_against_sources(&inner, &outer)
            .is_err()
    );
    assert_eq!(
        certificate.relation,
        surface::CoplanarConvexSurfaceContainment::RightInsideLeft
    );
    let mut reversed_left_hull = certificate.clone();
    reversed_left_hull.left_hull.reverse();
    assert!(reversed_left_hull.validate().is_err());
    let mut repeated_right_hull_point = certificate.clone();
    repeated_right_hull_point.right_hull[1] = repeated_right_hull_point.right_hull[0].clone();
    assert!(repeated_right_hull_point.validate().is_err());
    let mut outside_right_hull = certificate.clone();
    outside_right_hull.right_hull =
        vec![p3(10, 10, 0), p3(11, 10, 0), p3(11, 11, 0), p3(10, 11, 0)];
    assert!(outside_right_hull.validate().is_err());
    let report = surface::certify_coplanar_convex_surface_report(&outer, &inner);
    report.validate().unwrap();
    report.validate_against_sources(&outer, &inner).unwrap();
    assert_eq!(
        report.status,
        surface::CoplanarConvexSurfaceReportStatus::Contained(
            surface::CoplanarConvexSurfaceContainment::RightInsideLeft
        )
    );
    assert!(report.equivalence.is_none());
    assert!(report.containment.is_some());
    assert_eq!(
        report.validate_against_sources(&inner, &outer).unwrap_err(),
        surface::CoplanarConvexSurfaceReportError::SourceReplayMismatch
    );

    let holed = surface::arrange_coplanar_convex_surface_holed_difference(&outer, &inner)
        .expect("outer minus inner convex sheets should materialize one hole");
    holed.validate().unwrap();
    holed.validate_against_sources(&outer, &inner).unwrap();
    assert!(holed.validate_against_sources(&inner, &outer).is_err());
    assert_eq!(holed.outer.len(), 4);
    assert_eq!(holed.hole.len(), 4);
    assert_eq!(holed.mesh.vertices().len(), 8);
    let mut reversed_convex_outer = holed.clone();
    reversed_convex_outer.outer.reverse();
    assert!(reversed_convex_outer.validate().is_err());
    let mut reversed_convex_hole = holed.clone();
    reversed_convex_hole.hole.reverse();
    assert!(reversed_convex_hole.validate().is_err());
    let mut reversed_convex_mesh = holed.clone();
    reversed_convex_mesh.mesh = reverse_mesh_triangles(&reversed_convex_mesh.mesh);
    assert!(reversed_convex_mesh.validate().is_err());
    let mut filled_convex_hole_mesh = holed.clone();
    filled_convex_hole_mesh.mesh =
        mesh_with_filled_hole_triangle(&filled_convex_hole_mesh.mesh, holed.outer.len());
    assert!(filled_convex_hole_mesh.validate().is_err());
    let mut repeated_hole_point = holed.clone();
    repeated_hole_point.hole[1] = repeated_hole_point.hole[0].clone();
    assert!(repeated_hole_point.validate().is_err());
    let mut boundary_touching_hole = holed.clone();
    boundary_touching_hole.hole[0] = boundary_touching_hole.outer[0].clone();
    assert!(boundary_touching_hole.validate().is_err());
    let mut nonconvex_hole = holed.clone();
    nonconvex_hole.hole = vec![p3(1, 1, 0), p3(3, 1, 0), p3(1, 2, 0), p3(2, 3, 0)];
    assert!(nonconvex_hole.validate().is_err());
    let mut partial_convex_holed_mesh = holed.clone();
    let retained_points = partial_convex_holed_mesh
        .outer
        .iter()
        .chain(&partial_convex_holed_mesh.hole)
        .cloned()
        .collect::<Vec<_>>();
    partial_convex_holed_mesh.mesh = partial_mesh_from_points(&retained_points);
    assert!(partial_convex_holed_mesh.validate().is_err());
    if let Some(mesh) = retained_ring_crossing_mesh(&holed.mesh) {
        let mut crossing_ring_mesh = holed.clone();
        crossing_ring_mesh.mesh = mesh;
        assert!(crossing_ring_mesh.validate().is_err());
    }

    let preflight = hypermesh::preflight_boolean_exact(
        &outer,
        &inner,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let difference = hypermesh::boolean_exact(
        &outer,
        &inner,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    difference.validate().unwrap();
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(!difference.mesh.triangles().is_empty());
    assert!(exact_mesh_vertex_sets_equal(&difference.mesh, &holed.mesh));
    assert_eq!(
        difference.mesh.triangles().len(),
        holed.mesh.triangles().len()
    );

    let intersection = hypermesh::boolean_exact(
        &outer,
        &inner,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    intersection
        .validate_operation_against_sources(
            &outer,
            &inner,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(exact_mesh_vertex_sets_equal(&intersection.mesh, &inner));
    assert_eq!(intersection.mesh.triangles().len(), inner.triangles().len());
}

#[test]
fn exact_coplanar_arrangement_handles_large_tiled_surface_without_size_cap() {
    let left = tiled_rectangle_surface_i64(8, 7);
    let right = rect_surface_i64(&[(2, 2, 5, 5)]);
    assert!(left.triangles().len() + right.triangles().len() > 96);

    for operation in [
        hypermesh::ExactBooleanOperation::Union,
        hypermesh::ExactBooleanOperation::Intersection,
        hypermesh::ExactBooleanOperation::Difference,
    ] {
        let preflight = hypermesh::preflight_boolean_exact(&left, &right, operation).unwrap();
        preflight.validate().unwrap();
        preflight.validate_against_sources(&left, &right).unwrap();
        assert_eq!(
            preflight.support,
            hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
        );
        assert!(preflight.blocker.is_none());

        let result =
            hypermesh::boolean_exact(&left, &right, operation, ValidationPolicy::ALLOW_BOUNDARY)
                .unwrap();
        result
            .validate_operation_against_sources(
                &left,
                &right,
                operation,
                ValidationPolicy::ALLOW_BOUNDARY,
                hypermesh::ExactBoundaryBooleanPolicy::Reject,
            )
            .unwrap();
        assert_eq!(
            result.kind,
            hypermesh::ExactBooleanResultKind::CertifiedShortcut {
                shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
            }
        );

        if operation == hypermesh::ExactBooleanOperation::Intersection {
            assert!(exact_mesh_vertex_sets_equal(&result.mesh, &right));
            assert_eq!(result.mesh.triangles().len(), right.triangles().len());
        }
    }
}

#[test]
fn exact_coplanar_convex_surface_union_materializes_simple_loop() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 2, 0, 0, 2, 2, 0, 0, 2, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        &[1, 1, 0, 3, 1, 0, 3, 3, 0, 1, 3, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    assert!(surface::certify_coplanar_convex_surface_equivalence(&left, &right).is_none());
    assert!(surface::certify_coplanar_convex_surface_containment(&left, &right).is_none());
    let union = surface::arrange_coplanar_convex_surface_union(&left, &right)
        .expect("overlapping convex sheets should materialize one simple union loop");
    union.validate().unwrap();
    union
        .validate_against_sources(&left, &right, surface::CoplanarArrangementOperation::Union)
        .unwrap();
    assert!(
        union
            .validate_against_sources(
                &left,
                &right,
                surface::CoplanarArrangementOperation::Difference,
            )
            .is_err()
    );
    assert_eq!(union.polygon.len(), 8);
    assert!(!union.mesh.triangles().is_empty());
    let mut self_intersecting_union = union.clone();
    self_intersecting_union.polygon = vec![
        p3(0, 0, 0),
        p3(4, 4, 0),
        p3(0, 4, 0),
        p3(4, 0, 0),
        p3(5, 0, 0),
        p3(6, 0, 0),
        p3(6, 1, 0),
        p3(5, 1, 0),
    ];
    assert!(self_intersecting_union.validate().is_err());
    let mut partial_union_mesh = union.clone();
    partial_union_mesh.mesh = partial_mesh_from_points(&partial_union_mesh.polygon);
    assert!(partial_union_mesh.validate().is_err());

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    assert!(preflight.blocker.is_none());

    let arrangement_report = hypermesh::certify_planar_arrangement_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    arrangement_report.validate().unwrap();
    arrangement_report
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        arrangement_report.status,
        hypermesh::ExactPlanarArrangementStatus::AlreadyMaterialized
    );
    let winding_report = hypermesh::certify_winding_readiness_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    winding_report.validate().unwrap();
    winding_report
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(
        winding_report.status,
        hypermesh::ExactWindingReadinessStatus::PlanarArrangementAlreadyMaterialized
    );

    let result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    result.validate().unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(exact_mesh_vertex_sets_equal(&result.mesh, &union.mesh));
    assert_eq!(result.mesh.triangles().len(), union.mesh.triangles().len());

    let union_arrangement_report = hypermesh::certify_planar_arrangement_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
    )
    .unwrap();
    union_arrangement_report.validate().unwrap();
    assert_eq!(
        union_arrangement_report.status,
        hypermesh::ExactPlanarArrangementStatus::AlreadyMaterialized
    );

    let intersection = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    intersection.validate().unwrap();
    assert_eq!(
        intersection.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let intersection_output = surface::arrange_coplanar_convex_surface_intersection(&left, &right)
        .expect("overlapping convex sheets should materialize their convex intersection");
    intersection_output.validate().unwrap();
    intersection_output
        .validate_against_sources(
            &left,
            &right,
            surface::CoplanarArrangementOperation::Intersection,
        )
        .unwrap();
    assert_eq!(intersection_output.polygon.len(), 4);
    let intersection_result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    intersection_result.validate().unwrap();
    assert_eq!(
        intersection_result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(exact_mesh_vertex_sets_equal(
        &intersection_result.mesh,
        &intersection_output.mesh
    ));
    assert_eq!(
        intersection_result.mesh.triangles().len(),
        intersection_output.mesh.triangles().len()
    );

    let intersection_arrangement_report = hypermesh::certify_planar_arrangement_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    intersection_arrangement_report.validate().unwrap();
    assert_eq!(
        intersection_arrangement_report.status,
        hypermesh::ExactPlanarArrangementStatus::AlreadyMaterialized
    );
    let intersection_winding_report = hypermesh::certify_winding_readiness_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    intersection_winding_report.validate().unwrap();
    assert_eq!(
        intersection_winding_report.status,
        hypermesh::ExactWindingReadinessStatus::PlanarArrangementAlreadyMaterialized
    );

    let difference_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    difference_preflight.validate().unwrap();
    assert_eq!(
        difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    assert!(difference_preflight.blocker.is_none());
    let difference_arrangement_report = hypermesh::certify_planar_arrangement_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    difference_arrangement_report.validate().unwrap();
    assert_eq!(
        difference_arrangement_report.status,
        hypermesh::ExactPlanarArrangementStatus::AlreadyMaterialized
    );
}

#[test]
fn exact_coplanar_convex_surface_union_materializes_full_edge_touching_rectangles() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 2, 0, 0, 2, 2, 0, 0, 2, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        &[2, 0, 0, 4, 0, 0, 4, 2, 0, 2, 2, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    let union = surface::arrange_coplanar_convex_surface_union(&left, &right)
        .expect("full-edge touching convex sheets should replay as one exact rectangle");
    union.validate().unwrap();
    union
        .validate_against_sources(&left, &right, surface::CoplanarArrangementOperation::Union)
        .unwrap();
    assert_eq!(union.polygon.len(), 4);
    assert!(
        union
            .polygon
            .iter()
            .any(|point| real_eq(&point.x, &Real::from(0)))
    );
    assert!(
        union
            .polygon
            .iter()
            .any(|point| real_eq(&point.x, &Real::from(4)))
    );

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    preflight.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    result
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(exact_mesh_vertex_sets_equal(&result.mesh, &union.mesh));
    assert_eq!(result.mesh.triangles().len(), union.mesh.triangles().len());

    let point_touching_right = ExactMesh::from_i64_triangles_with_policy(
        &[2, 2, 0, 4, 2, 0, 4, 4, 0, 2, 4, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert!(surface::arrange_coplanar_convex_surface_union(&left, &point_touching_right).is_none());
    let point_union =
        surface::arrange_coplanar_surface_point_touch_union(&left, &point_touching_right)
            .expect("vertex-vertex point-touch surface union should retain two components");
    point_union.validate().unwrap();
    point_union
        .validate_union_against_sources(&left, &point_touching_right)
        .unwrap();
    assert_eq!(point_union.polygons.len(), 2);
    assert_eq!(point_union.mesh.vertices().len(), 8);
    assert_eq!(
        point_union
            .polygons
            .iter()
            .flatten()
            .filter(|point| real_eq(&point.x, &Real::from(2)) && real_eq(&point.y, &Real::from(2)))
            .count(),
        2
    );
    let point_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &point_touching_right,
        hypermesh::ExactBooleanOperation::Union,
    )
    .unwrap();
    point_preflight.validate().unwrap();
    assert_eq!(
        point_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let point_result = hypermesh::boolean_exact(
        &left,
        &point_touching_right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    point_result
        .validate_operation_against_sources(
            &left,
            &point_touching_right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        point_result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
}

#[test]
fn exact_coplanar_surface_point_touch_union_materializes_vertex_edge_contact() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 2, 0, 0, 2, 2, 0, 0, 2, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let vertex_edge_right = ExactMesh::from_i64_triangles_with_policy(
        &[1, 2, 0, 3, 3, 0, 3, 4, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    let union = surface::arrange_coplanar_surface_point_touch_union(&left, &vertex_edge_right)
        .expect("vertex-edge point contact should split the touched edge exactly");
    union.validate().unwrap();
    union
        .validate_union_against_sources(&left, &vertex_edge_right)
        .unwrap();
    assert_eq!(union.polygons.len(), 2);
    assert!(union.polygons.iter().any(|polygon| {
        polygon.len() == 5
            && polygon
                .iter()
                .any(|point| real_eq(&point.x, &Real::from(1)) && real_eq(&point.y, &Real::from(2)))
    }));
    let preflight = hypermesh::preflight_boolean_exact(
        &left,
        &vertex_edge_right,
        hypermesh::ExactBooleanOperation::Union,
    )
    .unwrap();
    preflight.validate().unwrap();
    preflight
        .validate_against_sources(&left, &vertex_edge_right)
        .unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
    let result = hypermesh::boolean_exact(
        &left,
        &vertex_edge_right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    result
        .validate_operation_against_sources(
            &left,
            &vertex_edge_right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
}

#[test]
fn exact_coplanar_nonconvex_surface_point_touch_union_materializes_branch_only_contact() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[
            0, 0, 0, 10, 0, 0, 10, 4, 0, 7, 4, 0, 6, 6, 0, 10, 8, 0, 10, 12, 0, 0, 12, 0,
        ],
        &[
            0, 1, 2, //
            0, 2, 3, //
            0, 3, 4, //
            0, 4, 7, //
            7, 4, 5, //
            7, 5, 6,
        ],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let point_touch_right = ExactMesh::from_i64_triangles_with_policy(
        &[10, 12, 0, 12, 12, 0, 12, 14, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    assert!(
        surface::arrange_coplanar_surface_component_union(&left, &point_touch_right,).is_none()
    );
    let union = surface::arrange_coplanar_surface_point_touch_union(&left, &point_touch_right)
        .expect("nonconvex source disk with branch-only point contact should materialize");
    union.validate().unwrap();
    union
        .validate_union_against_sources(&left, &point_touch_right)
        .unwrap();
    assert_eq!(union.polygons.len(), 2);
    assert!(union.polygons.iter().any(|polygon| polygon.len() > 4));
    assert_eq!(
        union
            .polygons
            .iter()
            .flatten()
            .filter(|point| real_eq(&point.x, &Real::from(10))
                && real_eq(&point.y, &Real::from(12)))
            .count(),
        2
    );

    for operation in [
        hypermesh::ExactBooleanOperation::Union,
        hypermesh::ExactBooleanOperation::Intersection,
        hypermesh::ExactBooleanOperation::Difference,
    ] {
        let preflight =
            hypermesh::preflight_boolean_exact(&left, &point_touch_right, operation).unwrap();
        preflight.validate().unwrap();
        preflight
            .validate_against_sources(&left, &point_touch_right)
            .unwrap();
        assert!(
            matches!(
                (operation, preflight.support),
                (
                    hypermesh::ExactBooleanOperation::Union,
                    hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
                ) | (
                    hypermesh::ExactBooleanOperation::Intersection,
                    hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
                ) | (
                    hypermesh::ExactBooleanOperation::Difference,
                    hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
                )
            ),
            "unexpected branch-only point-touch preflight support for {:?}: {:?}",
            operation,
            preflight.support
        );
        let result = hypermesh::boolean_exact(
            &left,
            &point_touch_right,
            operation,
            ValidationPolicy::ALLOW_BOUNDARY,
        )
        .unwrap();
        result
            .validate_operation_against_sources(
                &left,
                &point_touch_right,
                operation,
                ValidationPolicy::ALLOW_BOUNDARY,
                hypermesh::ExactBoundaryBooleanPolicy::Reject,
            )
            .unwrap();
    }
}

