#[test]
fn exact_coplanar_surface_component_union_materializes_nonconvex_contact_graph() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[
            3, 2, 0, 4, -2, 0, 5, 2, 0, //
            2, 5, 0, -2, 4, 0, 2, 3, 0,
        ],
        &[
            0, 1, 2, //
            3, 4, 5,
        ],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        &[2, 2, 0, 6, 2, 0, 6, 6, 0, 2, 6, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    assert!(surface::arrange_coplanar_convex_surface_union(&left, &right).is_none());
    assert!(surface::arrange_coplanar_convex_surface_component_union(&left, &right).is_none());
    assert!(surface::arrange_coplanar_convex_surface_multi_union(&left, &right).is_none());
    assert!(
        hypermesh::orthogonal_surface::arrange_coplanar_orthogonal_surface_union(&left, &right)
            .is_none()
    );
    assert!(
        hypermesh::affine_surface::arrange_coplanar_affine_surface_union(&left, &right).is_none()
    );

    let union = surface::arrange_coplanar_surface_component_union(&left, &right)
        .expect("non-rectilinear component contact graph should stitch one nonconvex loop");
    union.validate().unwrap();
    union
        .validate_component_union_against_sources(&left, &right)
        .unwrap();
    assert!(union.polygon.len() > 6);
    assert!(
        union
            .polygon
            .iter()
            .any(|point| real_eq(&point.x, &Real::from(4)) && real_eq(&point.y, &Real::from(-2)))
    );
    assert!(
        union
            .polygon
            .iter()
            .any(|point| real_eq(&point.x, &Real::from(-2)) && real_eq(&point.y, &Real::from(4)))
    );
    assert!(
        union
            .polygon
            .iter()
            .any(|point| real_eq(&point.x, &Real::from(2)) && real_eq(&point.y, &Real::from(2)))
    );

    let mut reversed = union.clone();
    reversed.polygon.reverse();
    assert!(reversed.validate().is_err());

    let mut convex_relabel = union.clone();
    convex_relabel.polygon = vec![p3(-2, -2, 0), p3(6, -2, 0), p3(6, 6, 0), p3(-2, 6, 0)];
    assert!(
        convex_relabel
            .validate_component_union_against_sources(&left, &right)
            .is_err()
    );

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    preflight.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    result
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(exact_mesh_vertex_sets_equal(&result.mesh, &union.mesh));
    assert_eq!(result.mesh.triangles().len(), union.mesh.triangles().len());

    let point_only_left = ExactMesh::from_i64_triangles_with_policy(
        &[
            2, 2, 0, 4, -2, 0, 6, -2, 0, //
            2, 6, 0, -2, 6, 0, -2, 4, 0,
        ],
        &[
            0, 1, 2, //
            3, 4, 5,
        ],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert!(surface::arrange_coplanar_surface_component_union(&point_only_left, &right).is_none());
    surface::arrange_coplanar_surface_point_touch_union(&point_only_left, &right)
        .expect("point-only component contact should route to explicit point-touch union")
        .validate_union_against_sources(&point_only_left, &right)
        .unwrap();
}

#[test]
fn exact_coplanar_surface_component_union_materializes_nonconvex_source_edge_contact() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[
            0, 0, 0, 10, 0, 0, 10, 4, 0, 7, 4, 0, 6, 6, 0, 10, 8, 0, 10, 12, 0, 0, 12, 0,
        ],
        &[
            0, 1, 2, //
            0, 2, 3, //
            0, 3, 4, //
            0, 4, 7, //
            7, 4, 5, //
            7, 5, 6,
        ],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        &[4, 12, 0, 8, 12, 0, 8, 14, 0, 4, 14, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    assert!(surface::arrange_coplanar_convex_surface_union(&left, &right).is_none());
    assert!(surface::arrange_coplanar_convex_surface_component_union(&left, &right).is_none());
    assert!(surface::arrange_coplanar_surface_point_touch_union(&left, &right).is_none());
    let union = surface::arrange_coplanar_surface_component_union(&left, &right)
        .expect("nonconvex source disk plus edge-attached component should stitch one loop");
    union.validate().unwrap();
    union
        .validate_component_union_against_sources(&left, &right)
        .unwrap();
    assert!(union.polygon.len() > 8);
    assert!(
        union.polygon.iter().any(|point| {
            real_eq(&point.x, &Real::from(4)) && real_eq(&point.y, &Real::from(14))
        })
    );
    assert!(
        union.polygon.iter().any(|point| {
            real_eq(&point.x, &Real::from(8)) && real_eq(&point.y, &Real::from(14))
        })
    );
    assert_eq!(
        union
            .polygon
            .iter()
            .filter(|point| real_eq(&point.y, &Real::from(12))
                && (real_eq(&point.x, &Real::from(4)) || real_eq(&point.x, &Real::from(8))))
            .count(),
        2
    );

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    preflight.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    result
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(exact_mesh_vertex_sets_equal(&result.mesh, &union.mesh));
    assert_eq!(result.mesh.triangles().len(), union.mesh.triangles().len());
}

#[test]
fn exact_coplanar_surface_boundary_touch_intersection_and_difference_are_lower_dimensional() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[
            0, 0, 0, 10, 0, 0, 10, 4, 0, 7, 4, 0, 6, 6, 0, 10, 8, 0, 10, 12, 0, 0, 12, 0,
        ],
        &[
            0, 1, 2, //
            0, 2, 3, //
            0, 3, 4, //
            0, 4, 7, //
            7, 4, 5, //
            7, 5, 6,
        ],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let boundary_touching_right = ExactMesh::from_i64_triangles_with_policy(
        &[4, 12, 0, 8, 12, 0, 8, 14, 0, 4, 14, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    assert!(
        surface::certify_coplanar_surface_boundary_touch(&left, &boundary_touching_right).is_some()
    );
    assert!(
        surface::arrange_coplanar_surface_point_touch_union(&left, &boundary_touching_right)
            .is_none()
    );

    let intersection_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &boundary_touching_right,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    intersection_preflight.validate().unwrap();
    intersection_preflight
        .validate_against_sources(&left, &boundary_touching_right)
        .unwrap();
    assert_eq!(
        intersection_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let intersection = hypermesh::boolean_exact(
        &left,
        &boundary_touching_right,
        hypermesh::ExactBooleanOperation::Intersection,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    intersection
        .validate_operation_against_sources(
            &left,
            &boundary_touching_right,
            hypermesh::ExactBooleanOperation::Intersection,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        intersection.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(intersection.mesh.triangles().is_empty());
    assert!(intersection.mesh.vertices().is_empty());

    let difference_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &boundary_touching_right,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    difference_preflight.validate().unwrap();
    difference_preflight
        .validate_against_sources(&left, &boundary_touching_right)
        .unwrap();
    assert_eq!(
        difference_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let difference = hypermesh::boolean_exact(
        &left,
        &boundary_touching_right,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    difference
        .validate_operation_against_sources(
            &left,
            &boundary_touching_right,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        difference.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(exact_mesh_vertex_sets_equal(&difference.mesh, &left));
    assert_eq!(difference.mesh.triangles().len(), left.triangles().len());

    let positive_area_overlap = ExactMesh::from_i64_triangles_with_policy(
        &[4, 10, 0, 8, 10, 0, 8, 14, 0, 4, 14, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert!(
        surface::certify_coplanar_surface_boundary_touch(&left, &positive_area_overlap).is_none()
    );
    let overlap_preflight = hypermesh::preflight_boolean_exact(
        &left,
        &positive_area_overlap,
        hypermesh::ExactBooleanOperation::Intersection,
    )
    .unwrap();
    assert_eq!(
        overlap_preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );
}

#[test]
fn exact_coplanar_surface_component_holed_union_materializes_annular_contact_graph() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[
            0, 4, 0, 0, 2, 0, 2, 0, 0, 4, 0, 0, //
            0, -4, 0, 0, -2, 0, -2, 0, 0, -4, 0, 0,
        ],
        &[
            0, 1, 2, 0, 2, 3, //
            4, 5, 6, 4, 6, 7,
        ],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        &[
            4, 0, 0, 2, 0, 0, 0, -2, 0, 0, -4, 0, //
            -4, 0, 0, -2, 0, 0, 0, 2, 0, 0, 4, 0,
        ],
        &[
            0, 1, 2, 0, 2, 3, //
            4, 5, 6, 4, 6, 7,
        ],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    assert!(surface::arrange_coplanar_convex_surface_union(&left, &right).is_none());
    assert!(surface::arrange_coplanar_convex_surface_component_union(&left, &right).is_none());
    assert!(surface::arrange_coplanar_surface_component_union(&left, &right).is_none());
    assert!(surface::arrange_coplanar_surface_multi_component_union(&left, &right).is_none());
    assert!(surface::arrange_coplanar_surface_point_touch_union(&left, &right).is_none());
    assert!(
        hypermesh::orthogonal_surface::arrange_coplanar_orthogonal_surface_union(&left, &right)
            .is_none()
    );
    assert!(
        hypermesh::affine_surface::arrange_coplanar_affine_surface_union(&left, &right).is_none()
    );

    let union = surface::arrange_coplanar_surface_component_holed_union(&left, &right)
        .expect("positive-length component contacts should materialize one annular union");
    union.validate().unwrap();
    union.validate_union_against_sources(&left, &right).unwrap();
    assert_eq!(union.components.len(), 1);
    assert_eq!(union.components[0].holes.len(), 1);
    assert_eq!(union.components[0].outer.len(), 4);
    assert_eq!(union.components[0].holes[0].len(), 4);
    assert!(
        union.components[0]
            .outer
            .iter()
            .any(|point| real_eq(&point.x, &Real::from(0)) && real_eq(&point.y, &Real::from(4)))
    );
    assert!(
        union.components[0].holes[0]
            .iter()
            .any(|point| real_eq(&point.x, &Real::from(0)) && real_eq(&point.y, &Real::from(2)))
    );

    let mut reversed_hole = union.clone();
    reversed_hole.components[0].holes[0].reverse();
    assert!(reversed_hole.validate().is_err());

    let mut stale_outer = union.clone();
    stale_outer.components[0].outer = vec![p3(-4, -4, 0), p3(4, -4, 0), p3(4, 4, 0), p3(-4, 4, 0)];
    assert!(
        stale_outer
            .validate_union_against_sources(&left, &right)
            .is_err()
    );

    let incomplete_right = ExactMesh::from_i64_triangles_with_policy(
        &[4, 0, 0, 2, 0, 0, 0, -2, 0, 0, -4, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert!(
        surface::arrange_coplanar_surface_component_holed_union(&left, &incomplete_right).is_none()
    );

    let point_only_disconnected_right = ExactMesh::from_i64_triangles_with_policy(
        &[
            4, 0, 0, 2, 0, 0, 0, -2, 0, 1, -3, 0, //
            -5, 0, 0, -3, 0, 0, -1, 2, 0, -1, 4, 0,
        ],
        &[
            0, 1, 2, 0, 2, 3, //
            4, 5, 6, 4, 6, 7,
        ],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert!(
        surface::arrange_coplanar_surface_component_holed_union(
            &left,
            &point_only_disconnected_right,
        )
        .is_none()
    );

    let preflight =
        hypermesh::preflight_boolean_exact(&left, &right, hypermesh::ExactBooleanOperation::Union)
            .unwrap();
    preflight.validate().unwrap();
    preflight.validate_against_sources(&left, &right).unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    result
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
    assert!(exact_mesh_vertex_sets_equal(&result.mesh, &union.mesh));
    assert_eq!(result.mesh.triangles().len(), union.mesh.triangles().len());
}

