#[test]
fn exact_coplanar_component_holed_difference_retains_hole_after_independent_openings() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 20, 0, 0, 20, 20, 0, 0, 20, 0],
        &[0, 1, 2, 0, 2, 3],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let independent_openings_plus_hole = ExactMesh::from_i64_triangles_with_policy(
        &[
            8, 8, 0, 12, 10, 0, 8, 12, 0, //
            0, 9, 0, 10, 8, 0, 10, 12, 0, 0, 11, 0, //
            12, 4, 0, 16, 6, 0, 12, 8, 0, //
            20, 5, 0, 14, 4, 0, 14, 8, 0, 20, 7, 0, //
            3, 15, 0, 5, 15, 0, 5, 17, 0, 3, 17, 0,
        ],
        &[
            0, 1, 2, //
            3, 4, 5, 3, 5, 6, //
            7, 8, 9, //
            10, 11, 12, 10, 12, 13, //
            14, 15, 16, 14, 16, 17,
        ],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    assert!(
        surface::arrange_coplanar_surface_cutter_hole_contact_difference(
            &left,
            &independent_openings_plus_hole,
        )
        .is_none()
    );
    let holed = surface::arrange_coplanar_convex_surface_component_holed_difference(
        &left,
        &independent_openings_plus_hole,
    )
    .expect("independent openings should retain unrelated strict holes");
    holed.validate().unwrap();
    holed
        .validate_against_sources(&left, &independent_openings_plus_hole)
        .unwrap();
    assert_eq!(holed.components.len(), 1);
    assert_eq!(holed.components[0].holes.len(), 1);
    assert!(holed.components[0].outer.len() > 14);
    assert!(
        holed.components[0].holes[0]
            .iter()
            .any(|point| real_eq(&point.x, &Real::from(3)) && real_eq(&point.y, &Real::from(15)))
    );

    let mut missing_hole = holed.clone();
    missing_hole.components[0].holes.clear();
    assert!(missing_hole.validate().is_err());

    let preflight = hypermesh::preflight_boolean_exact(
        &left,
        &independent_openings_plus_hole,
        hypermesh::ExactBooleanOperation::Difference,
    )
    .unwrap();
    preflight.validate().unwrap();
    preflight
        .validate_against_sources(&left, &independent_openings_plus_hole)
        .unwrap();
    assert_eq!(
        preflight.support,
        hypermesh::ExactBooleanSupport::CertifiedArrangementCellComplex
    );

    let result = hypermesh::boolean_exact(
        &left,
        &independent_openings_plus_hole,
        hypermesh::ExactBooleanOperation::Difference,
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    result
        .validate_operation_against_sources(
            &left,
            &independent_openings_plus_hole,
            hypermesh::ExactBooleanOperation::Difference,
            ValidationPolicy::ALLOW_BOUNDARY,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::CertifiedShortcut {
            shortcut: hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex
        }
    );
}

