#[test]
fn exact_intersection_graph_records_coplanar_edge_and_vertex_events() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 2, 0, 0, 0, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        &[1, 0, 0, 3, 0, 0, 1, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    let graph = build_intersection_graph(&left, &right).unwrap();

    graph.validate().unwrap();
    graph.validate_against_sources(&left, &right).unwrap();
    graph.face_pairs[0]
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(graph.face_pairs.len(), 1);
    assert_eq!(
        graph.face_pairs[0].relation,
        MeshFacePairRelation::CoplanarOverlapping
    );
    assert!(graph.face_pairs[0].projection.is_some());
    assert!(
        graph.face_pairs[0]
            .events
            .iter()
            .any(|event| matches!(event, IntersectionEvent::CoplanarEdge { .. }))
    );
    assert!(
        graph.face_pairs[0]
            .events
            .iter()
            .any(|event| matches!(event, IntersectionEvent::CoplanarVertex { .. }))
    );
    let overlap_graph = graph.face_pairs[0]
        .coplanar_overlap_graph()
        .expect("coplanar pair should expose an overlap graph");
    overlap_graph.validate().unwrap();
    overlap_graph
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(overlap_graph.left_face, 0);
    assert_eq!(overlap_graph.right_face, 0);
    assert_eq!(
        overlap_graph.relation,
        MeshFacePairRelation::CoplanarOverlapping
    );
    assert!(!overlap_graph.edge_overlaps.is_empty());
    assert!(!overlap_graph.vertex_overlaps.is_empty());
    assert_eq!(graph.coplanar_overlap_graphs(), vec![overlap_graph.clone()]);
    let mut stale_overlap_graph = overlap_graph.clone();
    stale_overlap_graph.left_face = usize::MAX;
    assert_eq!(
        stale_overlap_graph
            .validate_against_sources(&left, &right)
            .unwrap_err(),
        hypermesh::graph::CoplanarOverlapGraphValidationError::SourceReplayMismatch
    );
    let split_plan = graph.coplanar_overlap_split_plan(&left, &right).unwrap();
    split_plan.validate().unwrap();
    split_plan.validate_against_sources(&left, &right).unwrap();
    assert_eq!(split_plan.graphs.len(), 1);
    split_plan.graphs[0]
        .validate_against_sources(&left, &right)
        .unwrap();
    assert_eq!(split_plan.graphs[0].left_face, 0);
    assert_eq!(split_plan.graphs[0].right_face, 0);
    assert!(
        split_plan.graphs[0]
            .edge_splits
            .iter()
            .any(|split| split.interval_overlap || !split.points.is_empty())
    );
    assert!(
        split_plan.graphs[0]
            .edge_splits
            .iter()
            .filter(|split| split.interval_overlap)
            .all(|split| split.interval.as_ref().is_some_and(|interval| {
                compare_reals(
                    &interval.endpoints[0].left_parameter,
                    &interval.endpoints[1].left_parameter,
                )
                .value()
                    == Some(Ordering::Less)
            }))
    );
    let mut stale_split_plan = split_plan.clone();
    stale_split_plan.graphs[0].left_face = usize::MAX;
    assert_eq!(
        stale_split_plan
            .validate_against_sources(&left, &right)
            .unwrap_err(),
        hypermesh::graph::CoplanarOverlapSplitValidationError::SourceReplayMismatch
    );

    let readiness = graph
        .coplanar_arrangement_readiness_report(&left, &right)
        .unwrap();
    readiness.validate().unwrap();
    readiness.validate_against_sources(&left, &right).unwrap();
    assert!(readiness.needs_planar_cells());
    assert_eq!(
        readiness.status,
        hypermesh::graph::CoplanarArrangementReadinessStatus::NeedsPlanarCells
    );
    assert_eq!(readiness.graph_count, 1);
    assert_eq!(readiness.overlapping_graphs, 1);
    assert!(readiness.edge_overlap_count > 0);
    let separated = ExactMesh::from_i64_triangles_with_policy(
        &[5, 0, 0, 7, 0, 0, 5, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    assert_eq!(
        readiness
            .validate_against_sources(&left, &separated)
            .unwrap_err(),
        hypermesh::graph::CoplanarArrangementReadinessValidationError::SourceReplayMismatch
    );

    let mut relabeled_graph = graph.clone();
    relabeled_graph.face_pairs[0].left_face = usize::MAX;
    assert!(relabeled_graph.validate().is_ok());
    assert!(
        relabeled_graph
            .coplanar_arrangement_readiness_report(&left, &right)
            .is_err()
    );

    let mut relabeled_edge_graph = graph.clone();
    if let Some(IntersectionEvent::CoplanarEdge { left_edge, .. }) = relabeled_edge_graph
        .face_pairs
        .first_mut()
        .and_then(|pair| {
            pair.events
                .iter_mut()
                .find(|event| matches!(event, IntersectionEvent::CoplanarEdge { .. }))
        })
    {
        *left_edge = [usize::MAX, usize::MAX];
        assert!(relabeled_edge_graph.validate().is_ok());
        assert!(
            relabeled_edge_graph
                .coplanar_arrangement_readiness_report(&left, &right)
                .is_err()
        );
    }
}

#[test]
fn exact_planar_arrangement_evidence_reports_retained_obstacles() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 2, 0, 0, 0, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let overlapping = ExactMesh::from_i64_triangles_with_policy(
        &[1, 0, 0, 3, 0, 0, 1, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let point_touching = ExactMesh::from_i64_triangles_with_policy(
        &[2, 0, 0, 4, 0, 0, 2, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let separated = ExactMesh::from_i64_triangles_with_policy(
        &[5, 0, 0, 7, 0, 0, 5, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    let overlap_report = certify_planar_arrangement_evidence(&left, &overlapping).unwrap();
    overlap_report.validate().unwrap();
    overlap_report
        .validate_against_sources(&left, &overlapping)
        .unwrap();
    assert!(overlap_report.readiness.needs_planar_cells());
    assert!(overlap_report.obstacle.requires_general_arrangement());
    assert_eq!(overlap_report.split_graph_count, 1);
    assert!(overlap_report.split_edge_count > 0);
    assert!(overlap_report.left_branch_point_count <= overlap_report.branch_point_count);
    assert!(overlap_report.right_branch_point_count <= overlap_report.branch_point_count);
    assert!(overlap_report.mixed_side_branch_point_count <= overlap_report.left_branch_point_count);
    assert!(
        overlap_report.mixed_side_branch_point_count <= overlap_report.right_branch_point_count
    );

    let touching_report = certify_planar_arrangement_evidence(&left, &point_touching).unwrap();
    touching_report.validate().unwrap();
    touching_report
        .validate_against_sources(&left, &point_touching)
        .unwrap();
    assert_eq!(
        touching_report.readiness.status,
        hypermesh::graph::CoplanarArrangementReadinessStatus::BoundaryOnly
    );
    assert!(touching_report.point_only_contact_count > 0);
    assert!(matches!(
        touching_report.obstacle,
        PlanarArrangementObstacle::PointOnlyContact | PlanarArrangementObstacle::BranchPoint
    ));
    if touching_report.branch_point_count > 0 {
        assert!(touching_report.left_branch_point_count > 0);
        assert!(touching_report.right_branch_point_count > 0);
        assert!(touching_report.mixed_side_branch_point_count > 0);
    }

    let no_overlap_report = certify_planar_arrangement_evidence(&left, &separated).unwrap();
    no_overlap_report.validate().unwrap();
    no_overlap_report
        .validate_against_sources(&left, &separated)
        .unwrap();
    assert_eq!(
        no_overlap_report.obstacle,
        PlanarArrangementObstacle::NoCoplanarOverlap
    );
}

#[test]
fn exact_planar_arrangement_evidence_validation_rejects_stale_counts() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 2, 0, 0, 0, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        &[1, 0, 0, 3, 0, 0, 1, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let separated = ExactMesh::from_i64_triangles_with_policy(
        &[5, 0, 0, 7, 0, 0, 5, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    let report = certify_planar_arrangement_evidence(&left, &right).unwrap();
    assert_eq!(
        report.freshness_against_sources(&left, &right),
        ExactPlanarArrangementEvidenceFreshness::Current
    );
    let mut stale_vertex_count = report.clone();
    stale_vertex_count.vertex_overlap_count += 1;
    assert_eq!(
        stale_vertex_count.validate().unwrap_err(),
        ExactPlanarArrangementEvidenceError::VertexOverlapCountMismatch
    );
    assert_eq!(
        stale_vertex_count.freshness_against_sources(&left, &right),
        ExactPlanarArrangementEvidenceFreshness::StaleSplitCounts
    );

    let mut stale_obstacle = report.clone();
    stale_obstacle.obstacle = PlanarArrangementObstacle::NoCoplanarOverlap;
    assert_eq!(
        stale_obstacle.validate().unwrap_err(),
        ExactPlanarArrangementEvidenceError::ObstacleMismatch
    );
    assert_eq!(
        stale_obstacle.freshness_against_sources(&left, &right),
        ExactPlanarArrangementEvidenceFreshness::StaleObstacle
    );

    let mut stale_branch_side_count = report.clone();
    stale_branch_side_count.left_branch_point_count =
        stale_branch_side_count.branch_point_count.saturating_add(1);
    assert_eq!(
        stale_branch_side_count.validate().unwrap_err(),
        ExactPlanarArrangementEvidenceError::BranchSideCountMismatch
    );
    assert_eq!(
        stale_branch_side_count.freshness_against_sources(&left, &right),
        ExactPlanarArrangementEvidenceFreshness::StaleBranchPoints
    );

    assert_eq!(
        report
            .validate_against_sources(&left, &separated)
            .unwrap_err(),
        ExactPlanarArrangementEvidenceError::SourceReplayMismatch
    );
    assert_eq!(
        report.freshness_against_sources(&left, &separated),
        ExactPlanarArrangementEvidenceFreshness::SourceReplayMismatch
    );
}

#[test]
fn exact_coplanar_overlap_graph_validation_rejects_malformed_records() {
    let empty = hypermesh::graph::CoplanarOverlapGraph {
        left_face: 0,
        right_face: 0,
        relation: MeshFacePairRelation::CoplanarTouching,
        projection: hypermesh::CoplanarProjection::Xy,
        edge_overlaps: Vec::new(),
        vertex_overlaps: Vec::new(),
    };
    assert_eq!(
        empty.validate().unwrap_err(),
        hypermesh::graph::CoplanarOverlapGraphValidationError::EmptyOverlapGraph
    );

    let disjoint_edge = hypermesh::graph::CoplanarOverlapGraph {
        edge_overlaps: vec![hypermesh::graph::CoplanarEdgeOverlap {
            left_edge: [0, 1],
            right_edge: [2, 3],
            relation: hyperlimit::SegmentIntersection::Disjoint,
        }],
        ..empty.clone()
    };
    assert_eq!(
        disjoint_edge.validate().unwrap_err(),
        hypermesh::graph::CoplanarOverlapGraphValidationError::DisjointEdgeOverlap
    );

    let same_side_vertex = hypermesh::graph::CoplanarOverlapGraph {
        edge_overlaps: Vec::new(),
        vertex_overlaps: vec![hypermesh::graph::CoplanarVertexOverlap {
            vertex_side: MeshSide::Left,
            vertex: 0,
            triangle_side: MeshSide::Left,
            triangle_face: 0,
            location: hyperlimit::TriangleLocation::Inside,
        }],
        ..empty
    };
    assert_eq!(
        same_side_vertex.validate().unwrap_err(),
        hypermesh::graph::CoplanarOverlapGraphValidationError::SameSideVertexOverlap
    );
}

#[test]
fn exact_coplanar_arrangement_readiness_validation_rejects_bad_counts() {
    let mut no_overlap = hypermesh::graph::CoplanarArrangementReadinessReport {
        status: hypermesh::graph::CoplanarArrangementReadinessStatus::NoCoplanarOverlap,
        graph_count: 0,
        overlapping_graphs: 0,
        touching_graphs: 0,
        edge_overlap_count: 0,
        vertex_overlap_count: 0,
        point_split_count: 0,
        interval_overlap_count: 0,
        interval_endpoint_count: 0,
    };
    no_overlap.validate().unwrap();

    no_overlap.edge_overlap_count = 1;
    assert_eq!(
        no_overlap.validate().unwrap_err(),
        hypermesh::graph::CoplanarArrangementReadinessValidationError::NoOverlapWithEvidence
    );

    let mismatch = hypermesh::graph::CoplanarArrangementReadinessReport {
        status: hypermesh::graph::CoplanarArrangementReadinessStatus::NeedsPlanarCells,
        graph_count: 2,
        overlapping_graphs: 1,
        touching_graphs: 0,
        edge_overlap_count: 1,
        vertex_overlap_count: 0,
        point_split_count: 0,
        interval_overlap_count: 0,
        interval_endpoint_count: 0,
    };
    assert_eq!(
        mismatch.validate().unwrap_err(),
        hypermesh::graph::CoplanarArrangementReadinessValidationError::GraphCountMismatch
    );

    let missing_overlap = hypermesh::graph::CoplanarArrangementReadinessReport {
        status: hypermesh::graph::CoplanarArrangementReadinessStatus::NeedsPlanarCells,
        graph_count: 1,
        overlapping_graphs: 0,
        touching_graphs: 1,
        edge_overlap_count: 1,
        vertex_overlap_count: 0,
        point_split_count: 0,
        interval_overlap_count: 0,
        interval_endpoint_count: 0,
    };
    assert_eq!(
        missing_overlap.validate().unwrap_err(),
        hypermesh::graph::CoplanarArrangementReadinessValidationError::NeedsCellsMissingOverlap
    );

    let impossible_split_summary = hypermesh::graph::CoplanarArrangementReadinessReport {
        status: hypermesh::graph::CoplanarArrangementReadinessStatus::NeedsPlanarCells,
        graph_count: 1,
        overlapping_graphs: 1,
        touching_graphs: 0,
        edge_overlap_count: 1,
        vertex_overlap_count: 0,
        point_split_count: 1,
        interval_overlap_count: 1,
        interval_endpoint_count: 2,
    };
    assert_eq!(
        impossible_split_summary.validate().unwrap_err(),
        hypermesh::graph::CoplanarArrangementReadinessValidationError::SplitCountExceedsEdgeEvidence
    );

    let impossible_interval_endpoint_count = hypermesh::graph::CoplanarArrangementReadinessReport {
        status: hypermesh::graph::CoplanarArrangementReadinessStatus::NeedsPlanarCells,
        graph_count: 1,
        overlapping_graphs: 1,
        touching_graphs: 0,
        edge_overlap_count: 1,
        vertex_overlap_count: 0,
        point_split_count: 0,
        interval_overlap_count: 1,
        interval_endpoint_count: 1,
    };
    assert_eq!(
        impossible_interval_endpoint_count.validate().unwrap_err(),
        hypermesh::graph::CoplanarArrangementReadinessValidationError::IntervalEndpointCountMismatch
    );
}

#[test]
fn exact_coplanar_overlap_split_validation_rejects_malformed_records() {
    let point = Point3::new(Real::from(0), Real::from(0), Real::from(0));
    let missing_point = hypermesh::graph::CoplanarEdgeSplitConstruction {
        overlap: hypermesh::graph::CoplanarEdgeOverlap {
            left_edge: [0, 1],
            right_edge: [2, 3],
            relation: hyperlimit::SegmentIntersection::Proper,
        },
        points: Vec::new(),
        interval_overlap: false,
        interval: None,
    };
    assert_eq!(
        missing_point.validate().unwrap_err(),
        hypermesh::graph::CoplanarOverlapSplitValidationError::MissingPointConstruction
    );

    let missing_interval = hypermesh::graph::CoplanarEdgeSplitConstruction {
        overlap: hypermesh::graph::CoplanarEdgeOverlap {
            left_edge: [0, 1],
            right_edge: [2, 3],
            relation: hyperlimit::SegmentIntersection::CollinearOverlap,
        },
        points: Vec::new(),
        interval_overlap: false,
        interval: None,
    };
    assert_eq!(
        missing_interval.validate().unwrap_err(),
        hypermesh::graph::CoplanarOverlapSplitValidationError::MissingIntervalConstruction
    );

    let proper_with_endpoint_parameter = hypermesh::graph::CoplanarEdgeSplitConstruction {
        overlap: hypermesh::graph::CoplanarEdgeOverlap {
            left_edge: [0, 1],
            right_edge: [2, 3],
            relation: hyperlimit::SegmentIntersection::Proper,
        },
        points: vec![hypermesh::graph::CoplanarEdgeSplitPoint {
            point: point.clone(),
            left_parameter: Real::from(0),
            right_parameter: half(),
        }],
        interval_overlap: false,
        interval: None,
    };
    assert_eq!(
        proper_with_endpoint_parameter.validate().unwrap_err(),
        hypermesh::graph::CoplanarOverlapSplitValidationError::ProperCrossingEndpointParameter
    );

    let endpoint_with_interior_parameters = hypermesh::graph::CoplanarEdgeSplitConstruction {
        overlap: hypermesh::graph::CoplanarEdgeOverlap {
            left_edge: [0, 1],
            right_edge: [2, 3],
            relation: hyperlimit::SegmentIntersection::EndpointTouch,
        },
        points: vec![hypermesh::graph::CoplanarEdgeSplitPoint {
            point,
            left_parameter: half(),
            right_parameter: half(),
        }],
        interval_overlap: false,
        interval: None,
    };
    assert_eq!(
        endpoint_with_interior_parameters.validate().unwrap_err(),
        hypermesh::graph::CoplanarOverlapSplitValidationError::EndpointTouchWithoutEndpointParameter
    );

    let missing_interval_endpoints = hypermesh::graph::CoplanarEdgeSplitConstruction {
        overlap: hypermesh::graph::CoplanarEdgeOverlap {
            left_edge: [0, 1],
            right_edge: [2, 3],
            relation: hyperlimit::SegmentIntersection::Identical,
        },
        points: Vec::new(),
        interval_overlap: true,
        interval: None,
    };
    assert_eq!(
        missing_interval_endpoints.validate().unwrap_err(),
        hypermesh::graph::CoplanarOverlapSplitValidationError::MissingIntervalEndpoints
    );

    let corrupted_point = hypermesh::graph::CoplanarEdgeSplitConstruction {
        overlap: hypermesh::graph::CoplanarEdgeOverlap {
            left_edge: [0, 1],
            right_edge: [2, 3],
            relation: hyperlimit::SegmentIntersection::Proper,
        },
        points: vec![hypermesh::graph::CoplanarEdgeSplitPoint {
            point: Point3::new(Real::from(2), Real::from(0), Real::from(0)),
            left_parameter: half(),
            right_parameter: half(),
        }],
        interval_overlap: false,
        interval: None,
    };
    let left_edge = [
        Point3::new(Real::from(0), Real::from(0), Real::from(0)),
        Point3::new(Real::from(1), Real::from(0), Real::from(0)),
    ];
    let right_edge = [
        Point3::new(half(), Real::from(-1), Real::from(0)),
        Point3::new(half(), Real::from(1), Real::from(0)),
    ];
    assert_eq!(
        corrupted_point
            .validate_against_edges(left_edge, right_edge)
            .unwrap_err(),
        hypermesh::graph::CoplanarOverlapSplitValidationError::SplitPointDoesNotMatchLeftParameter
    );
}

#[test]
fn exact_coplanar_split_plan_replays_interval_endpoints_against_sources() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 4, 0, 0, 0, 4, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        &[1, 0, 0, 3, 0, 0, 1, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    let graph = build_intersection_graph(&left, &right).unwrap();
    let split_plan = graph.coplanar_overlap_split_plan(&left, &right).unwrap();
    split_plan.validate_against_meshes(&left, &right).unwrap();

    let mut corrupted = split_plan.clone();
    let interval = corrupted
        .graphs
        .iter_mut()
        .flat_map(|graph| graph.edge_splits.iter_mut())
        .find_map(|split| split.interval.as_mut())
        .expect("overlapping collinear edge interval");
    interval.endpoints[0].point = Point3::new(Real::from(-1), Real::from(0), Real::from(0));

    let err = corrupted
        .validate_against_meshes(&left, &right)
        .unwrap_err();
    assert!(err.diagnostics.iter().any(|diagnostic| {
        diagnostic
            .message
            .contains("SplitPointDoesNotMatchLeftParameter")
    }));
}

