#[test]
fn exact_arrangement_boolean_attempt_reports_decline_stage() {
    let left = ExactMesh::from_i64_triangles_with_policy(
        &[0, 0, 0, 2, 0, 0, 0, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();
    let right = ExactMesh::from_i64_triangles_with_policy(
        &[4, 0, 0, 6, 0, 0, 4, 2, 0],
        &[0, 1, 2],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .unwrap();

    let report = hypermesh::exact_arrangement_boolean_attempt_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        hypermesh::ExactRegularizationPolicy::REGULARIZED_SOLID,
    )
    .unwrap();

    assert_eq!(
        report.stage,
        hypermesh::ExactArrangementBooleanStage::Materialized
    );
    assert!(report.arrangement_blockers > 0);
    assert_eq!(
        report.materialized_shortcut,
        Some(hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex)
    );
    assert_eq!(report.face_cells, 2);
    assert_eq!(report.regions, 2);
    assert_eq!(report.volume_regions, 0);
    assert_eq!(report.volume_adjacencies, 0);
    assert_eq!(report.lower_dimensional_artifacts, 0);
    assert_eq!(report.selected_faces, 0);
    assert_eq!(report.selected_volume_regions, 0);
    assert_eq!(report.output_vertices, 6);
    assert_eq!(report.output_triangles, 2);
    assert_eq!(report.decline, None);
}

