#[test]
fn exact_arrangement_regularizes_unregularized_sheet_complex_without_winding_fallback() {
    let left = tetrahedron_i64([0, 0, 0], [4, 0, 0], [0, 4, 0], [0, 0, 4]);
    let right = tetrahedron_i64([1, 1, 0], [5, 1, 0], [1, 5, 0], [1, 1, 4]);

    let arrangement = hypermesh::ExactArrangement::from_meshes_with_policy(
        &left,
        &right,
        hypermesh::ExactRegularizationPolicy::REGULARIZED_SOLID,
    )
    .unwrap();
    assert!(
        arrangement
            .blockers
            .contains(&hypermesh::ExactArrangementBlocker::UnregularizedCoincidentSheetComplex)
    );
    assert!(
        arrangement
            .blockers
            .contains(&hypermesh::ExactArrangementBlocker::UnregularizedOpenSheetComplex)
    );

    let report = hypermesh::exact_arrangement_boolean_attempt_report(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        hypermesh::ExactRegularizationPolicy::REGULARIZED_SOLID,
    )
    .unwrap();

    assert_eq!(
        report.stage,
        hypermesh::ExactArrangementBooleanStage::Materialized
    );
    assert_eq!(report.decline, None);
    assert_eq!(
        report.materialized_shortcut,
        Some(hypermesh::ExactBooleanShortcutKind::ArrangementCellComplex)
    );
    assert_eq!(report.arrangement_blockers, 0);
    assert!(report.output_vertices > 0);
    assert!(report.output_triangles > 0);

    let result = hypermesh::boolean_exact(
        &left,
        &right,
        hypermesh::ExactBooleanOperation::Union,
        ValidationPolicy::CLOSED,
    )
    .unwrap();
    assert_eq!(
        result.kind,
        hypermesh::ExactBooleanResultKind::ArrangementCellComplexMaterialized {
            operation: hypermesh::ExactBooleanOperation::Union
        }
    );
    result
        .validate_operation_against_sources(
            &left,
            &right,
            hypermesh::ExactBooleanOperation::Union,
            ValidationPolicy::CLOSED,
            hypermesh::ExactBoundaryBooleanPolicy::Reject,
        )
        .unwrap();
}

fn fuzz_seed_mesh_pair(seed: &[u8]) -> (ExactMesh, ExactMesh) {
    let mut values = Vec::new();
    let mut indices = Vec::new();

    for chunk in seed.chunks_exact(2).take(36) {
        let raw = i16::from_le_bytes(chunk.try_into().unwrap()) as i32;
        values.push((raw.rem_euclid(257) - 128) as i64);
    }
    for chunk in seed.chunks_exact(2).skip(36).take(36) {
        indices.push((u16::from_le_bytes(chunk.try_into().unwrap()) % 12) as usize);
    }

    let left_value_end = values.len() / 2 / 3 * 3;
    let right_value_start = left_value_end;
    let right_value_len = (values.len() - right_value_start) / 3 * 3;
    let left_index_end = indices.len() / 2 / 3 * 3;
    let right_index_start = left_index_end;
    let right_index_len = (indices.len() - right_index_start) / 3 * 3;

    let left = ExactMesh::from_i64_triangles_with_policy(
        &values[..left_value_end],
        &indices[..left_index_end],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .expect("reduced fuzz seed left mesh should remain constructible");
    let right = ExactMesh::from_i64_triangles_with_policy(
        &values[right_value_start..right_value_start + right_value_len],
        &indices[right_index_start..right_index_start + right_index_len],
        ValidationPolicy::ALLOW_BOUNDARY,
    )
    .expect("reduced fuzz seed right mesh should remain constructible");
    (left, right)
}
